// ─── OFFLINE PUFFER ─────────────────────────────────────────────
function initOffline(){window.addEventListener('online',()=>{document.getElementById('offline-banner')?.classList.remove('show');replayOfflineQueue();});window.addEventListener('offline',()=>{document.getElementById('offline-banner')?.classList.add('show');});}
async function checkOverdueNotifications(){if(!('Notification'in window)||Notification.permission==='denied')return;const lastCheck=localStorage.getItem('_notifCheck');const today=heute();if(lastCheck===today)return;try{const{data:auf}=await sb.from('aufgaben').select('titel').eq('status','offen').lt('faellig',today).limit(10);if(!auf||!auf.length)return;localStorage.setItem('_notifCheck',today);const perm=Notification.permission==='granted'?'granted':await Notification.requestPermission();if(perm!=='granted')return;new Notification('Baumanager – Überfällige Aufgaben',{body:`${auf.length} Aufgabe${auf.length>1?'n':''} überfällig: ${auf.slice(0,3).map(a=>a.titel).join(', ')}${auf.length>3?' ...':''}`,icon:'/favicon.ico'});}catch{}}
function offlineQueue(){try{return JSON.parse(localStorage.getItem('_offlineQ')||'[]');}catch{return[];}}
function offlineQueueAdd(op){const q=offlineQueue();q.push({...op,ts:Date.now()});if(q.length>100)q.splice(0,q.length-100);localStorage.setItem('_offlineQ',JSON.stringify(q));}
async function replayOfflineQueue(){const q=offlineQueue();if(!q.length)return;let remaining=[];for(const op of q){try{if(op.type==='insert')await sb.from(op.table).insert(op.data);else if(op.type==='update')await sb.from(op.table).update(op.data).eq('id',op.id);else if(op.type==='delete')await sb.from(op.table).delete().eq('id',op.id);}catch{remaining.push(op);}}localStorage.setItem('_offlineQ',JSON.stringify(remaining));if(remaining.length<q.length){const savedCount=q.length-remaining.length;if(savedCount>0)console.log(`Offline-Puffer: ${savedCount} Aktionen synchronisiert`);}}
// ─── AUDIT LOG ──────────────────────────────────────────────────
function logAudit(aktion,tabelle,label){try{const log=JSON.parse(localStorage.getItem('_audit')||'[]');log.unshift({ts:new Date().toISOString(),aktion,tabelle,label,user:me?.email||'?'});if(log.length>300)log.length=300;localStorage.setItem('_audit',JSON.stringify(log));}catch{}}
async function pgStat(){ld();try{const[r1,r2,r3,r4]=await Promise.all([sb.from('rechnungen').select('betrag,status,created_at'),sb.from('aufgaben').select('status,faellig,created_at'),sb.from('leads').select('status'),sb.from('stunden').select('stunden,datum')]);const rech=r1.data||[],auf=r2.data||[],leads=r3.data||[],std=r4.data||[];const now=new Date();const moL=['Jan','Feb','Mrz','Apr','Mai','Jun','Jul','Aug','Sep','Okt','Nov','Dez'];const monate=[];for(let i=5;i>=0;i--){const d=new Date(now.getFullYear(),now.getMonth()-i,1);monate.push({yr:d.getFullYear(),mo:d.getMonth(),label:moL[d.getMonth()]});}const moUmsatz=monate.map(m=>{const sum=rech.filter(r=>{const d=new Date(r.created_at);return d.getFullYear()===m.yr&&d.getMonth()===m.mo;}).reduce((s,r)=>s+parseFloat(r.betrag||0),0);return{...m,sum};});const maxU=Math.max(...moUmsatz.map(m=>m.sum),1);const offenA=auf.filter(a=>a.status==='offen').length;const erlA=auf.filter(a=>a.status==='erledigt').length;const uebA=auf.filter(a=>a.status==='offen'&&a.faellig&&a.faellig<heute()).length;const rateA=auf.length?Math.round(erlA/auf.length*100):0;const totalPaid=rech.filter(r=>r.status==='bezahlt').reduce((s,r)=>s+parseFloat(r.betrag||0),0);const funnel=[['neu','Neu'],['kontaktiert','Kontaktiert'],['termin','Termin'],['vor_ort','Vor Ort'],['angebot','Angebot'],['gewonnen','Gewonnen']].map(([k,l])=>({k,label:l,count:leads.filter(x=>x.status===k).length}));const maxL=Math.max(...funnel.map(f=>f.count),1);const stdM=std.filter(s=>{const d=new Date(s.datum||now.toISOString().split('T')[0]);return d.getFullYear()===now.getFullYear()&&d.getMonth()===now.getMonth();});const totalStdM=stdM.reduce((s,r)=>s+(parseFloat(r.stunden)||0),0);sC(`<div class="ph"><div><div class="pt">Statistik</div><div class="ps">Auswertung & Kennzahlen</div></div></div><div class="kpi-grid" style="margin-bottom:20px"><div class="kpi-card" onclick="go('rech')" style="cursor:pointer"><div class="kpi-label">Umsatz bezahlt</div><div class="kpi-val-sm">${fmtEur(totalPaid)}</div></div><div class="kpi-card${uebA>0?' kpi-alert':''}" onclick="go('auf')" style="cursor:pointer"><div class="kpi-label">Erledigungsrate</div><div class="kpi-val">${rateA}%</div><div class="kpi-sub">${erlA} von ${auf.length} erledigt</div></div><div class="kpi-card" onclick="go('std')" style="cursor:pointer"><div class="kpi-label">Stunden (Monat)</div><div class="kpi-val">${totalStdM.toFixed(1)} h</div></div><div class="kpi-card" onclick="go('leads')" style="cursor:pointer"><div class="kpi-label">Leads gewonnen</div><div class="kpi-val">${leads.filter(l=>l.status==='gewonnen').length}</div><div class="kpi-sub">von ${leads.length} gesamt</div></div></div><div class="tc" style="margin-bottom:16px"><div class="th"><span class="th-t">Rechnungen – letzte 6 Monate</span></div><div style="padding:16px 16px 8px"><div style="display:flex;align-items:flex-end;gap:6px;height:90px">${moUmsatz.map(m=>`<div style="flex:1;background:${m.sum>0?'var(--p)':'var(--border)'};border-radius:3px 3px 0 0;height:${m.sum>0?Math.max(6,Math.round(m.sum/maxU*88))+'px':'3px'};min-width:0;transition:height 0.3s" title="${fmtEur(m.sum)}"></div>`).join('')}</div><div style="display:flex;gap:6px;margin-top:6px">${moUmsatz.map(m=>`<div style="flex:1;text-align:center;font-size:10px;color:var(--text-ter);font-weight:600;min-width:0">${m.label}</div>`).join('')}</div></div></div><div class="tc" style="margin-bottom:16px"><div class="th"><span class="th-t">Lead Pipeline</span></div><div style="padding:12px 16px;display:flex;flex-direction:column;gap:10px">${funnel.map(f=>`<div><div style="display:flex;justify-content:space-between;margin-bottom:4px"><div style="font-size:12px;font-weight:600;color:var(--text-sec)">${f.label}</div><div style="font-size:12px;font-weight:700;color:var(--text)">${f.count}</div></div><div style="height:7px;background:var(--bg);border-radius:4px;overflow:hidden"><div style="height:100%;background:var(--p);border-radius:4px;width:${f.count?Math.max(4,Math.round(f.count/maxL*100)):0}%"></div></div></div>`).join('')}</div></div><div class="tc" style="margin-bottom:16px"><div class="th"><span class="th-t">Aufgaben Status</span></div><div style="padding:16px;display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;text-align:center"><div><div style="font-size:26px;font-weight:800;color:var(--p)">${offenA}</div><div style="font-size:11px;color:var(--text-ter);font-weight:700;text-transform:uppercase;margin-top:4px">Offen</div></div><div><div style="font-size:26px;font-weight:800;color:var(--red)">${uebA}</div><div style="font-size:11px;color:var(--text-ter);font-weight:700;text-transform:uppercase;margin-top:4px">Überfällig</div></div><div><div style="font-size:26px;font-weight:800;color:var(--green)">${erlA}</div><div style="font-size:11px;color:var(--text-ter);font-weight:700;text-transform:uppercase;margin-top:4px">Erledigt</div></div></div></div>`);}catch(e){sC(`<div class="em"><div class="em-t">Fehler: ${e.message}</div></div>`);}}

function pgAuditLog(){const log=JSON.parse(localStorage.getItem('_audit')||'[]');const icons={erstellt:'→',bearbeitet:'✎',gelöscht:'×'};sC(`<div class="ph"><div><div class="pt">Aktivitätsprotokoll</div><div class="ps">${log.length} Einträge (lokal)</div></div><button class="bp" style="background:var(--bg);color:var(--red);border:1px solid var(--red)" onclick="if(confirm('Protokoll löschen?')){localStorage.removeItem('_audit');pgAuditLog();}">Löschen</button></div>${!log.length?'<div class="em"><div class="em-t">Keine Einträge</div></div>':`<div class="tc"><table><thead><tr><th>Zeit</th><th>Aktion</th><th>Bereich</th><th>Eintrag</th></tr></thead><tbody>${log.slice(0,100).map(e=>`<tr><td style="font-size:11px;white-space:nowrap;color:var(--text-ter)">${new Date(e.ts).toLocaleString('de-DE',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'})}</td><td><span style="font-size:12px;font-weight:700;color:${e.aktion==='gelöscht'?'var(--red)':e.aktion==='erstellt'?'var(--green)':'var(--p)'}">${e.aktion}</span></td><td style="color:var(--text-sec)">${e.tabelle}</td><td style="max-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${e.label||'—'}</td></tr>`).join('')}</tbody></table></div>`}`);}
// ─── AUFGABEN VORLAGEN ──────────────────────────────────────────
const AUF_VORLAGEN=[{titel:'Angebot erstellen',prioritaet:'A'},{titel:'Vor-Ort-Termin vereinbaren',prioritaet:'A'},{titel:'Rechnung ausstellen',prioritaet:'B'},{titel:'Rückruf',prioritaet:'B'},{titel:'Mängel prüfen',prioritaet:'A'},{titel:'Angebot nachfassen',prioritaet:'B'},{titel:'Fotos machen',prioritaet:'C'},{titel:'Objektkontrolle',prioritaet:'C'},{titel:'Wartungsprotokoll erstellen',prioritaet:'C'}];
function getVorlagen(){try{const c=JSON.parse(localStorage.getItem('_aufVorlagen')||'[]');return[...AUF_VORLAGEN,...c];}catch{return AUF_VORLAGEN;}}
function addVorlage(titel,prio){if(!titel.trim()){alert('Bitte zuerst einen Titel eingeben.');return;}try{const v=JSON.parse(localStorage.getItem('_aufVorlagen')||'[]');if(v.find(x=>x.titel===titel)||AUF_VORLAGEN.find(x=>x.titel===titel)){alert('Vorlage existiert bereits.');return;}v.push({titel:titel.trim(),prioritaet:prio||'B',custom:true});localStorage.setItem('_aufVorlagen',JSON.stringify(v));alert('Vorlage gespeichert!');const w=document.getElementById('auf-vorlagen');if(w&&w.style.display!=='none')mVorlagenRefresh();}catch{}}
function delVorlagePgIdx(i){try{const v=JSON.parse(localStorage.getItem('_aufVorlagen')||'[]');v.splice(i,1);localStorage.setItem('_aufVorlagen',JSON.stringify(v));pgVorlagenEinst();}catch{}}
const heute=()=>new Date().toISOString().split('T')[0];
const fmtDatum=(d)=>{if(!d)return'-';const p=d.split('-');return p.length===3?`${p[2]}.${p[1]}.${p[0]}`:d;};
const fmtEur=(n)=>new Intl.NumberFormat('de-DE',{minimumFractionDigits:2,maximumFractionDigits:2}).format(parseFloat(n)||0)+' €';
const fmtTel=(t)=>t?`<a href="tel:${t}" style="color:var(--p);text-decoration:none;font-weight:500">${t}</a>`:'-';
const xBtn=`<button onclick="cM()" style="width:32px;height:32px;background:var(--bg);border:1px solid var(--border);border-radius:8px;cursor:pointer;display:flex;align-items:center;justify-content:center;color:var(--text-sec);font-size:18px;flex-shrink:0">×</button>`;
const modalHeader=(title)=>`<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:20px;padding-bottom:14px;border-bottom:1px solid var(--border-l)"><div style="font-size:17px;font-weight:700;color:var(--text)">${title}</div>${xBtn}</div>`;
async function dL(){const e=document.getElementById('le').value.trim(),p=document.getElementById('lp').value;const er=document.getElementById('lerr');er.textContent='';if(!e||!p){er.textContent='Bitte alle Felder ausfüllen.';return;}const b=document.querySelector('.bl');b.textContent='...';b.disabled=true;const{data,error}=await sb.auth.signInWithPassword({email:e,password:p});b.textContent='Anmelden';b.disabled=false;if(error){er.textContent='Falsche Zugangsdaten.';return;}sA(data.user);}
async function dLo(){await sb.auth.signOut();location.reload();}
async function loadBadgeCounts(){try{const today=heute();const[{count:ueb},{count:neu}]=await Promise.all([sb.from('aufgaben').select('id',{count:'exact',head:true}).eq('status','offen').lt('faellig',today),sb.from('anfragen').select('id',{count:'exact',head:true}).eq('status','neu')]);const total=(ueb||0)+(neu||0);const badge=document.getElementById('notif-badge');if(!badge)return;if(total>0){badge.textContent=total>99?'99+':String(total);badge.style.display='flex';}else{badge.style.display='none';}}catch{}}async function sA(u){me=u;document.getElementById('ls').style.display='none';document.getElementById('app').style.display='block';document.getElementById('tb').style.display='flex';document.getElementById('tab-bar').style.display='flex';document.getElementById('ue').textContent=u.email;document.getElementById('ua').textContent=u.email[0].toUpperCase();loadSettings();await loadMitarbeiter();go('dash');checkOverdueNotifications();loadBadgeCounts();}
async function loadMitarbeiter(){try{const{data}=await sb.from('mitarbeiter').select('*').order('name');if(data)_mitarbeiter=data;}catch(e){_mitarbeiter=[];}}
const titles={dash:'Dashboard',stat:'Statistik',suche:'Suche',leads:'Akquise',vert:'Verträge',kalk:'Kalkulation',karte:'Berlin Karte',auf:'Aufgaben',kunden:'Kunden',proj:'Projekte',obj:'Objekte',termine:'Termine',angebote:'Angebote',mit:'Mitarbeiter',std:'Stunden',mat:'Material',rech:'Rechnungen',einst:'Einstellungen',anf:'Anfragen',ben:'Benutzer & Rollen',audit:'Aktivitätslog'};
function go(p){if(window._leafletMap){window._leafletMap.remove();window._leafletMap=null;}document.querySelectorAll('.ni').forEach(el=>el.classList.toggle('active',el.dataset.p===p));document.querySelectorAll('.tab-item[data-tab]').forEach(el=>el.classList.toggle('active',el.dataset.tab===p));document.getElementById('tt').textContent=titles[p]||p;cSB();({dash:pgDash,kalk:pgKalk,vert:pgVertraege,leads:pgLeads,karte:pgKarte,auf:pgAufgaben,kunden:pgKunden,proj:pgProj,obj:pgObjekte,termine:pgTermine,angebote:pgAngebote,mit:pgMit,std:pgStd,mat:pgMat,rech:pgRech,einst:pgEinst,anf:pgAnfragen,ben:pgBenutzer,audit:pgAuditLog,stat:pgStat,suche:pgSuche})[p]?.();}
function tSB(){document.getElementById('sb').classList.toggle('open');document.getElementById('ov').classList.toggle('show');}
function cSB(){document.getElementById('sb').classList.remove('open');document.getElementById('ov').classList.remove('show');}
