async function pgSAEinst(){ld();await loadSALeistungen();const gewerke=Object.keys(_saLeistungen).length>0?Object.keys(_saLeistungen):Object.keys(GEWERK_LEISTUNGEN);sC(`<div class="ph"><div><div class="pt">Schnellangebot Preise</div><div class="ps">Gewerke & Leistungen anpassen</div></div><button class="bp" onclick="mSANeuesGewerk()">+ Neues Gewerk</button></div><div style="background:var(--p-light);border-radius:12px;padding:12px 14px;margin-bottom:16px;font-size:12px;color:var(--p);font-weight:600">💡 Preise anpassen, Leistungen hinzufügen oder eigene Gewerke erstellen.</div><div class="gr">${gewerke.map(g=>{const leistungen=_saLeistungen[g]||GEWERK_LEISTUNGEN[g]||[];const isCustom=!!_saLeistungen[g];return`<div class="ca"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px"><div style="font-size:14px;font-weight:700;color:var(--text)">${g}</div><div style="display:flex;gap:6px"><button onclick="mSANeueLeistung('${g}')" style="padding:4px 10px;background:var(--p);color:#fff;border:none;border-radius:7px;font-size:11px;font-weight:600;cursor:pointer">+ Leistung</button>${isCustom?`<button onclick="delSAGewerk('${g}')" style="padding:4px 10px;background:var(--bg);border:1px solid var(--red);color:var(--red);border-radius:7px;font-size:11px;font-weight:600;cursor:pointer">🗑️</button>`:''}</div></div><div style="display:flex;flex-direction:column;gap:4px">${leistungen.map(l=>`<div style="display:flex;justify-content:space-between;align-items:center;padding:8px 10px;background:var(--bg);border-radius:8px;font-size:12px"><span style="color:var(--text);font-weight:500">${l.name}</span><div style="display:flex;align-items:center;gap:8px"><span style="color:var(--text-sec)">${typeof l.preis==='number'?l.preis.toFixed(2).replace('.',','):l.preis} € / ${l.einheit}</span><button onclick='mSAEditLeistung(${JSON.stringify(l).replace(/'/g,"&#39;")}, "${g}")' style="background:none;border:none;cursor:pointer;color:var(--p);font-size:12px">✏️</button>${l.id?`<button onclick="delSALeistung('${l.id}','${g}')" style="background:none;border:none;cursor:pointer;color:var(--red);font-size:12px">🗑️</button>`:''}</div></div>`).join('')}</div></div>`;}).join('')}`);
}
function mSANeuesGewerk(){oM(`${modalHeader('Neues Gewerk')}<div class="fg"><label>GEWERK NAME *</label><input id="sa-gw-name" placeholder="z.B. Parkettarbeiten"></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveSANeuesGewerk()">Speichern</button></div>`);}
async function saveSANeuesGewerk(){const name=document.getElementById('sa-gw-name').value.trim();if(!name){alert('Name fehlt!');return;}const{error}=await sb.from('schnellangebot_leistungen').insert({user_id:me.id,gewerk:name,name:'Neue Leistung',einheit:'m²',preis:0,sort_order:0});if(error){alert('Fehler: '+error.message);return;}cM();pgSAEinst();}
async function delSAGewerk(gewerk){if(!confirm(`Gewerk "${gewerk}" löschen?`))return;await sb.from('schnellangebot_leistungen').delete().eq('gewerk',gewerk).eq('user_id',me.id);pgSAEinst();}
function mSANeueLeistung(gewerk){oM(`${modalHeader('Neue Leistung – '+gewerk)}<div class="fg"><label>NAME *</label><input id="sa-l-name" placeholder="z.B. Grundierung"></div><div class="fr"><div class="fg"><label>PREIS (€)</label><input id="sa-l-preis" type="number" step="0.5" placeholder="0,00"></div><div class="fg"><label>EINHEIT</label><select id="sa-l-einheit"><option value="m²">m²</option><option value="Std">Std</option><option value="lfm">lfm</option><option value="Stk">Stk</option><option value="m³">m³</option><option value="pauschal">pauschal</option><option value="Woche">Woche</option></select></div></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveSALeistung(null,'${gewerk}')">Speichern</button></div>`);}
function mSAEditLeistung(l,gewerk){oM(`${modalHeader('Leistung bearbeiten')}<div class="fg"><label>NAME *</label><input id="sa-l-name" value="${l.name||''}"></div><div class="fr"><div class="fg"><label>PREIS (€)</label><input id="sa-l-preis" type="number" step="0.5" value="${l.preis||0}"></div><div class="fg"><label>EINHEIT</label><select id="sa-l-einheit"><option value="m²" ${l.einheit==='m²'?'selected':''}>m²</option><option value="Std" ${l.einheit==='Std'?'selected':''}>Std</option><option value="lfm" ${l.einheit==='lfm'?'selected':''}>lfm</option><option value="Stk" ${l.einheit==='Stk'?'selected':''}>Stk</option><option value="m³" ${l.einheit==='m³'?'selected':''}>m³</option><option value="pauschal" ${l.einheit==='pauschal'?'selected':''}>pauschal</option><option value="Woche" ${l.einheit==='Woche'?'selected':''}>Woche</option></select></div></div><div class="ma">${l.id?`<button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delSALeistung('${l.id}','${gewerk}')">Löschen</button>`:'<button class="bc" onclick="cM()">Abbrechen</button>'}<button class="bs" onclick="saveSALeistung('${l.id||''}','${gewerk}')">Speichern</button></div>`);}
async function saveSALeistung(id,gewerk){const name=document.getElementById('sa-l-name').value.trim();if(!name){alert('Name fehlt!');return;}const o={user_id:me.id,gewerk,name,preis:parseFloat(document.getElementById('sa-l-preis').value)||0,einheit:document.getElementById('sa-l-einheit').value};const{error}=id?await sb.from('schnellangebot_leistungen').update(o).eq('id',id):await sb.from('schnellangebot_leistungen').insert(o);if(error){alert('Fehler: '+error.message);return;}cM();pgSAEinst();}
async function delSALeistung(id,gewerk){if(!confirm('Leistung löschen?'))return;await sb.from('schnellangebot_leistungen').delete().eq('id',id);cM();pgSAEinst();}
