anfragen:anf.length?`<div class="section-hdr"><span class="section-hdr-title">Neue Anfragen</span><button class="section-hdr-link" onclick="go('anf')">Alle</button></div><div class="tc" style="margin-bottom:16px">${anf.map(a=>`<div style="display:flex;align-items:center;gap:12px;padding:11px 16px;border-bottom:1px solid var(--border-l);cursor:pointer" onclick="go('anf')"><div style="flex:1"><div style="font-size:13px;font-weight:600;color:var(--text)">${a.name||'Anfrage'}</div></div><span class="bd bd-b">Neu</span></div>`).join('')}</div>`:'',
