async function pgProjDetail(id){ld();try{const[{data:p},{data:bt},{data:mat},{data:std},{data:ang},{data:abn}]=await Promise.all([sb.from('projekte').select('*').eq('id',id).single(),sb.from('bautagebuch').select('*').eq('projekt_id',id).order('datum',{ascending:false}),sb.from('material').select('*').eq('projekt_id',id),sb.from('stunden').select('*').eq('projekt_id',id),sb.from('angebote').select('*').eq('projekt_id',id),sb.from('abnahmen').select('*').eq('projekt_id',id).order('datum',{ascending:false})]);const kostenStunden=(std||[]).reduce((s,r)=>{const mit=_mitarbeiter.find(m=>m.name===r.mitarbeiter_name);const satz=r.stundensatz||mit?.stundensatz||0;return s+(parseFloat(r.stunden)||0)*satz;},0);const kostenMaterial=(mat||[]).reduce((s,r)=>s+(parseFloat(r.preis)||0),0);const gesamtStunden=(std||[]).reduce((s,r)=>s+(parseFloat(r.stunden)||0),0);const gesamtKosten=kostenStunden+kostenMaterial;const mapQ=encodeURIComponent(p?.adresse||'Berlin');sC(`<button class="bk" onclick="pgProj()">← Zurück</button><div class="ph"><div><div class="pt">${p?.name||'Projekt'}</div><div class="ps">${p?.kunde||p?.kunde_name||''} ${p?.adresse?'· '+p.adresse:''}</div></div><button class="bp" onclick="mProjEdit('${id}')" style="background:var(--bg);color:var(--text);border:1px solid var(--border)">Bearbeiten</button></div><div class="kosten-box"><div class="kosten-box-header"><span class="kosten-box-title">Kostenübersicht</span><span style="font-size:11px;color:var(--text-ter)">automatisch berechnet</span></div><div class="kosten-row"><span class="kosten-label">Stunden (${gesamtStunden.toFixed(1)} h)</span><span class="kosten-val">${fmtEur(kostenStunden)}</span></div><div class="kosten-row"><span class="kosten-label">Material (${(mat||[]).length} Pos.)</span><span class="kosten-val">${fmtEur(kostenMaterial)}</span></div><div class="kosten-total"><span class="kosten-total-label">Gesamtkosten</span><span class="kosten-total-val">${fmtEur(gesamtKosten)}</span></div><div class="kosten-actions"><button class="kosten-btn kosten-btn-ang" onclick="angAusKosten('${id}','${p?.name||''}','${p?.kunde||p?.kunde_name||''}',${kostenStunden},${kostenMaterial})">→ Angebot</button><button class="kosten-btn kosten-btn-rech" onclick="rechAusKosten('${id}','${p?.kunde||p?.kunde_name||''}',${gesamtKosten})">→ Rechnung</button></div></div>${p?.adresse?`<div class="map-wrap"><iframe src="https://maps.google.com/maps?q=${mapQ}&output=embed&z=15" allowfullscreen></iframe></div>`:''}<div class="sh">Bautagebuch (${(bt||[]).length})</div><div class="tc" style="overflow-x:auto"><div class="th"><span class="th-t">Einträge</span><button class="bp" style="padding:6px 12px;font-size:12px" onclick="mBt('${id}')">+ Eintrag</button></div><table><thead><tr><th>Datum</th><th>Beschreibung</th><th>Zeit</th><th></th></tr></thead><tbody>${!(bt&&bt.length)?'<tr><td colspan="4"><div class="em" style="padding:20px"><div class="em-t">Keine Einträge</div></div></td></tr>':bt.map(e=>`<tr><td>${fmtDatum(e.datum)}</td><td style="max-width:140px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${e.beschreibung||'-'}</td><td style="white-space:nowrap;color:var(--text-sec)">${e.zeit_von||'-'} – ${e.zeit_bis||'-'}</td><td style="white-space:nowrap"><button onclick="loadAndExportBt('${e.id}','${p?.name||''}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--text-sec)">📄</button><button onclick="delBt('${e.id}','${id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red)">🗑️</button></td></tr>`).join('')}</tbody></table></div><div class="sh">Abnahmen (${(abn||[]).length})</div><div class="tc" style="overflow-x:auto"><div class="th"><span class="th-t">Abnahmen</span><button class="bp" style="padding:6px 12px;font-size:12px;background:var(--green)" onclick="mAbnahme('${id}','${p?.name||''}','${p?.kunde||p?.kunde_name||''}')">+ Abnahme</button></div><table><thead><tr><th>Datum</th><th>Auftraggeber</th><th>Mängel</th><th></th></tr></thead><tbody>${!(abn&&abn.length)?'<tr><td colspan="4"><div class="em" style="padding:20px"><div class="em-t">Keine Abnahmen</div></div></td></tr>':abn.map(a=>`<tr><td>${fmtDatum(a.datum)}</td><td>${a.auftraggeber||'-'}</td><td>${a.maengel?'<span class="bd bd-r">Ja</span>':'<span class="bd bd-g">Keine</span>'}</td><td><button onclick="exportAbnahmePDF(${JSON.stringify(a).replace(/'/g,'&#39;').replace(/"/g,'&quot;')})" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--text-sec)">📄</button></td></tr>`).join('')}</tbody></table></div><div class="sh">Angebote (${(ang||[]).length})</div><div class="tc" style="overflow-x:auto"><div class="th"><span class="th-t">Angebote</span><button class="bp" style="padding:6px 12px;font-size:12px" onclick="mAng('${id}','${p?.kunde||p?.kunde_name||''}')">+ Angebot</button></div><table><thead><tr><th>Nr.</th><th>Titel</th><th>Betrag</th><th>Status</th><th></th></tr></thead><tbody>${!(ang&&ang.length)?'<tr><td colspan="5"><div class="em" style="padding:20px"><div class="em-t">Keine Angebote</div></div></td></tr>':ang.map(a=>`<tr style="cursor:pointer" onclick="mAngEdit('${a.id}','${id}')"><td style="font-family:monospace;font-size:11px;color:var(--text-ter)">${a.nummer||'-'}</td><td>${a.titel||'-'}</td><td><b>${fmtEur(a.gesamt)}</b></td><td><span class="bd ${a.status==='angenommen'?'bd-g':a.status==='abgelehnt'?'bd-r':'bd-o'}">${a.status||'offen'}</span></td><td style="white-space:nowrap"><button onclick="event.stopPropagation();angToRech('${a.id}','${id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--text-sec)" title="Zu Rechnung">🧾</button><button onclick="event.stopPropagation();delAng('${a.id}','${id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red)">🗑️</button></td></tr>`).join('')}</tbody></table></div><div class="sh">Material (${(mat||[]).length})</div><div class="tc" style="overflow-x:auto"><div class="th"><span class="th-t">Material</span><button class="bp" style="padding:6px 12px;font-size:12px" onclick="mMat2('${id}')">+ Material</button></div><table><thead><tr><th>Material</th><th>Menge</th><th>Preis</th><th></th></tr></thead><tbody>${!(mat&&mat.length)?'<tr><td colspan="4"><div class="em" style="padding:20px"><div class="em-t">Kein Material</div></div></td></tr>':mat.map(m=>`<tr onclick="mMatEdit('${m.id}','${m.name||''}','${m.menge||''}','${m.preis||''}')" style="cursor:pointer"><td><span style="font-weight:500">${m.name||'-'}</span></td><td style="color:var(--text-sec)">${m.menge||'-'}</td><td>${m.preis?fmtEur(m.preis):'-'}</td><td><button onclick="event.stopPropagation();delMat('${m.id}','${id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red)">🗑️</button></td></tr>`).join('')}</tbody></table></div><div class="sh">Stunden (${(std||[]).length})</div><div class="tc" style="overflow-x:auto"><div class="th"><span class="th-t">Stunden</span><button class="bp" style="padding:6px 12px;font-size:12px" onclick="mStd2('${id}')">+ Stunden</button></div><table><thead><tr><th>Datum</th><th>Mitarbeiter</th><th>Std</th><th>Kosten</th><th></th></tr></thead><tbody>${!(std&&std.length)?'<tr><td colspan="5"><div class="em" style="padding:20px"><div class="em-t">Keine Stunden</div></div></td></tr>':std.map(s=>{const mit=_mitarbeiter.find(m=>m.name===s.mitarbeiter_name);const satz=s.stundensatz||mit?.stundensatz||0;const kosten=(parseFloat(s.stunden)||0)*satz;return`<tr style="cursor:pointer" onclick="mStdEdit('${s.id}','${s.mitarbeiter_name||''}','${s.datum||''}','${s.stunden||0}','${satz}','${id}')"><td>${fmtDatum(s.datum)}</td><td>${s.mitarbeiter_name||'-'}</td><td><b>${s.stunden||0} h</b></td><td>${satz>0?fmtEur(kosten):'-'}</td><td><button onclick="event.stopPropagation();delStd('${s.id}','${id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red)">🗑️</button></td></tr>`;}).join('')}</tbody></table></div><div class="sh">Fotos</div><div class="photo-up" onclick="document.getElementById('fi').click()"><input type="file" id="fi" accept="image/*" multiple style="display:none" onchange="upFotos('${id}')"><div style="font-size:20px;margin-bottom:4px">📷</div><div style="font-size:13px;font-weight:500">Fotos hinzufügen</div></div><div id="fp" class="photo-prev"></div>`);}catch(e){sC(`<div class="em"><div class="em-t">Fehler beim Laden: ${e.message}</div><div style="margin-top:8px"><button class="bp" onclick="pgProj()">← Zurück</button></div></div>`);}}
async function mAngEdit(aid,pid){const{data:a}=await sb.from('angebote').select('*').eq('id',aid).single();if(!a)return;const pos=JSON.parse(a.positionen||'[]');oM(`${modalHeader('Angebot bearbeiten')}<div class="fr"><div class="fg"><label>ANGEBOTSNR.</label><input id="f-nr" value="${a.nummer||''}"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${a.datum||heute()}"></div></div><div class="fg"><label>TITEL *</label><input id="f-t" value="${a.titel||''}"></div><div class="fg"><label>KUNDE</label><input id="f-ku" value="${a.kunde||''}"></div><div class="fg"><label>POSITIONEN</label><div id="pos-wrap">${pos.map(p=>`<div class="offer-row"><input value="${p.name||''}" class="pos-name"><input value="${p.preis||0}" type="number" class="pos-price price-inp" oninput="calcTotal()"></div>`).join('')}</div><button type="button" onclick="addPos()" style="margin-top:6px;padding:8px 14px;background:var(--bg);border:1.5px dashed var(--border);border-radius:var(--radius);font-size:12px;font-weight:600;cursor:pointer;color:var(--text-sec);width:100%">+ Position</button><div class="offer-total">Gesamt: <span id="tot">${fmtEur(a.gesamt)}</span></div></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="offen"${a.status==='offen'?' selected':''}>Offen</option><option value="angenommen"${a.status==='angenommen'?' selected':''}>Angenommen</option><option value="abgelehnt"${a.status==='abgelehnt'?' selected':''}>Abgelehnt</option></select></div><div style="margin-bottom:10px"><button onclick="exportAngPDF('${aid}')" style="width:100%;padding:11px;background:var(--p-light);color:var(--p);border:1.5px solid var(--p);border-radius:10px;font-size:14px;font-weight:700;cursor:pointer">📤 Als PDF teilen / herunterladen</button></div><div class="ma"><button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delAng('${aid}','${pid}');cM()">Löschen</button><button class="bs" onclick="saveAngEdit('${aid}','${pid}')">Speichern</button></div>`);}
async function saveAngEdit(aid,pid){const t=document.getElementById('f-t').value.trim();if(!t){alert('Titel fehlt!');return;}const ns=document.querySelectorAll('.pos-name'),ps=document.querySelectorAll('.pos-price');const pos=[];let total=0;ns.forEach((n,i)=>{if(n.value.trim()){const pr=parseFloat(ps[i].value)||0;pos.push({name:n.value,preis:pr});total+=pr;}});const{error}=await sb.from('angebote').update({nummer:document.getElementById('f-nr').value,titel:t,kunde:document.getElementById('f-ku').value,datum:document.getElementById('f-d').value,positionen:JSON.stringify(pos),gesamt:total,status:document.getElementById('f-s').value}).eq('id',aid);if(error){alert('Fehler: '+error.message);return;}cM();pgProjDetail(pid);}
function mStdEdit(id,name,datum,stunden,satz,pid){const mitOpts=_mitarbeiter.map(m=>`<option value="${m.name}" data-satz="${m.stundensatz||0}"${m.name===name?' selected':''}>${m.name}</option>`).join('');oM(`${modalHeader('Stunden bearbeiten')}<div class="fg"><label>MITARBEITER</label><select id="f-n" onchange="updateSatz(this)"><option value="">— Wählen —</option>${mitOpts}</select></div><div class="fg"><label>STUNDENSATZ (€/h)</label><input id="f-satz" type="number" step="0.5" value="${satz||''}"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${datum||heute()}"></div><div class="fg"><label>STUNDEN *</label><input id="f-s" type="number" step="0.5" value="${stunden||''}"></div><div class="ma"><button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delStd('${id}','${pid}');cM()">Löschen</button><button class="bs" onclick="saveStdEdit('${id}','${pid}')">Speichern</button></div>`);}
async function saveStdEdit(id,pid){const s=document.getElementById('f-s').value;if(!s){alert('Stunden fehlen!');return;}const satz=parseFloat(document.getElementById('f-satz').value)||0;const{error}=await sb.from('stunden').update({mitarbeiter_name:document.getElementById('f-n').value,datum:document.getElementById('f-d').value,stunden:parseFloat(s),stundensatz:satz,kosten:(parseFloat(s)||0)*satz}).eq('id',id);if(error){alert('Fehler: '+error.message);return;}cM();pgProjDetail(pid);}
async function angAusKosten(pid,pname,kunde,kostenStd,kostenMat){const nr='A-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);const pos=[];if(kostenStd>0)pos.push({name:'Lohnkosten',preis:kostenStd});if(kostenMat>0)pos.push({name:'Materialkosten',preis:kostenMat});const gesamt=kostenStd+kostenMat;oM(`${modalHeader('Angebot aus Projektkosten')}<div style="background:var(--p-light);border-radius:10px;padding:12px;margin-bottom:16px"><div style="font-size:13px;font-weight:600;color:var(--p)">${pname||'Projekt'}</div><div style="font-size:12px;color:var(--text-sec);margin-top:3px">Lohn: ${fmtEur(kostenStd)} · Material: ${fmtEur(kostenMat)}</div></div><div class="fr"><div class="fg"><label>ANGEBOTSNR.</label><input id="f-nr" value="${nr}"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${heute()}"></div></div><div class="fg"><label>TITEL *</label><input id="f-t" value="Arbeiten ${pname||''}"></div><div class="fg"><label>KUNDE</label><input id="f-ku" value="${kunde||''}"></div><div class="fg"><label>POSITIONEN</label><div id="pos-wrap">${pos.map(p=>`<div class="offer-row"><input value="${p.name}" class="pos-name"><input value="${p.preis.toFixed(2)}" type="number" class="pos-price price-inp" oninput="calcTotal()"></div>`).join('')}</div><button type="button" onclick="addPos()" style="margin-top:6px;padding:8px 14px;background:var(--bg);border:1.5px dashed var(--border);border-radius:var(--radius);font-size:12px;font-weight:600;cursor:pointer;color:var(--text-sec);width:100%">+ Position</button><div class="offer-total">Gesamt: <span id="tot">${fmtEur(gesamt)}</span></div></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveAngMitPid('${pid}')">Speichern</button></div>`);}
async function saveAngMitPid(pid){const t=document.getElementById('f-t').value.trim();if(!t){alert('Titel fehlt!');return;}const ns=document.querySelectorAll('.pos-name'),ps=document.querySelectorAll('.pos-price');const pos=[];let total=0;ns.forEach((n,i)=>{if(n.value.trim()){const pr=parseFloat(ps[i].value)||0;pos.push({name:n.value,preis:pr});total+=pr;}});const{error}=await sb.from('angebote').insert({nummer:document.getElementById('f-nr').value,titel:t,projekt_id:pid,kunde:document.getElementById('f-ku').value,datum:document.getElementById('f-d').value,positionen:JSON.stringify(pos),gesamt:total,status:'offen',user_id:me.id});if(error){alert('Fehler: '+error.message);return;}cM();pgProjDetail(pid);}
async function rechAusKosten(pid,kunde,betrag){const mwst=settings.mwst||19;const brutto=Math.round(betrag*(1+mwst/100)*100)/100;if(!confirm(`Rechnung erstellen?\nNetto: ${fmtEur(betrag)}\nMwSt (${mwst}%): ${fmtEur(brutto-betrag)}\nBrutto: ${fmtEur(brutto)}`))return;const nr='RE-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);const{error}=await sb.from('rechnungen').insert({rechnungsnummer:nr,projekt_id:pid,kunde:kunde,datum:heute(),betrag:brutto,status:'offen'});if(error){alert('Fehler: '+error.message);return;}if(confirm('Rechnung erstellt! Jetzt zur Rechnung?'))go('rech');else pgProjDetail(pid);}
async function angToRech(aid,pid){const{data:a}=await sb.from('angebote').select('*').eq('id',aid).single();if(!a)return;const mwst=settings.mwst||19;const brutto=Math.round(a.gesamt*(1+mwst/100)*100)/100;if(!confirm(`Angebot in Rechnung umwandeln?\nNetto: ${fmtEur(a.gesamt)}\nMwSt (${mwst}%): ${fmtEur(brutto-a.gesamt)}\nBrutto: ${fmtEur(brutto)}`))return;const nr='RE-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);const{error}=await sb.from('rechnungen').insert({rechnungsnummer:nr,projekt_id:pid||a.projekt_id,kunde:a.kunde,datum:heute(),betrag:brutto,status:'offen'});if(error){alert('Fehler: '+error.message);return;}await sb.from('angebote').update({status:'angenommen'}).eq('id',aid);if(confirm('Rechnung erstellt! Jetzt zur Rechnung?'))go('rech');else pgProjDetail(pid);}
async function mProjEdit(id){const{data:p}=await sb.from('projekte').select('*').eq('id',id).single();const{data:ku}=await sb.from('kunden').select('id,name');oM(`${modalHeader('Projekt bearbeiten')}<div class="fg"><label>PROJEKTNAME *</label><input id="f-n" value="${p.name||''}"></div><div class="fg"><label>KUNDE</label><select id="f-ku"><option value="">- Kein Kunde -</option>${(ku||[]).map(k=>`<option value="${k.id}" data-n="${k.name}"${k.id===p.kunden_id?' selected':''}>${k.name}</option>`).join('')}</select></div><div class="fg"><label>ADRESSE</label><input id="f-adr" value="${p.adresse||''}"></div><div class="fg"><label>STATUS</label><select id="f-st"><option value="Aktiv"${p.status==='Aktiv'?' selected':''}>Aktiv</option><option value="Pausiert"${p.status==='Pausiert'?' selected':''}>Pausiert</option><option value="Abgeschlossen"${p.status==='Abgeschlossen'?' selected':''}>Abgeschlossen</option></select></div><div class="fg"><label>BESCHREIBUNG</label><textarea id="f-desc" rows="3">${p.beschreibung||''}</textarea></div><div class="fr"><div class="fg"><label>START</label><input id="f-start" type="date" value="${p.datum_start||''}"></div><div class="fg"><label>ENDE</label><input id="f-end" type="date" value="${p.datum_end||''}"></div></div><div class="ma"><button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delProj('${id}')">Löschen</button><button class="bs" onclick="saveProjEdit('${id}')">Speichern</button></div>`);}
async function saveProjEdit(id){const n=document.getElementById('f-n').value.trim();if(!n){alert('Projektname fehlt!');return;}const s=document.getElementById('f-ku');const ki=s.value||null,kn=ki?s.options[s.selectedIndex].dataset.n:'';const{error}=await sb.from('projekte').update({name:n,kunden_id:ki,kunde_name:kn,kunde:kn,adresse:document.getElementById('f-adr').value,beschreibung:document.getElementById('f-desc').value,status:document.getElementById('f-st').value,datum_start:document.getElementById('f-start').value||null,datum_end:document.getElementById('f-end').value||null}).eq('id',id);if(error){alert('Fehler: '+error.message);return;}cM();pgProjDetail(id);}
async function upFotos(pid){const files=document.getElementById('fi').files;const prev=document.getElementById('fp');for(const f of files){const r=new FileReader();r.onload=e=>{const i=document.createElement('img');i.src=e.target.result;i.className='pt-img';i.onclick=()=>window.open(e.target.result,'_blank');i.style.cursor='pointer';prev.appendChild(i);};r.readAsDataURL(f);await sb.storage.from('fotos').upload(`${pid}/${Date.now()}_${f.name}`,f).catch(()=>{});}}
async function delBt(id,pid){if(!confirm('Eintrag löschen?'))return;await sb.from('bautagebuch').delete().eq('id',id);pgProjDetail(pid);}
async function delMat(id,pid){if(!confirm('Material löschen?'))return;await sb.from('material').delete().eq('id',id);pgProjDetail(pid);}
async function delStd(id,pid){if(!confirm('Stunden löschen?'))return;await sb.from('stunden').delete().eq('id',id);pgProjDetail(pid);}
async function delAng(id,pid){if(!confirm('Angebot löschen?'))return;await sb.from('angebote').delete().eq('id',id);pgProjDetail(pid);}
function mMatEdit(id,name,menge,preis){oM(`${modalHeader('Material bearbeiten')}<div class="fg"><label>MATERIALNAME *</label><input id="f-n" value="${name}"></div><div class="fr"><div class="fg"><label>MENGE</label><input id="f-m" value="${menge}"></div><div class="fg"><label>PREIS</label><input id="f-pr" type="number" step="0.01" value="${preis}"></div></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveMatEdit('${id}')">Speichern</button></div>`);}
async function saveMatEdit(id){const n=document.getElementById('f-n').value.trim();if(!n){alert('Name fehlt!');return;}const{error}=await sb.from('material').update({name:n,menge:document.getElementById('f-m').value,preis:parseFloat(document.getElementById('f-pr').value)||null}).eq('id',id);if(error){alert('Fehler: '+error.message);return;}cM();pgMat();}
async function pgTermine(){ld();try{const h=new Date();const[{data},{data:proj}]=await Promise.all([sb.from('termine').select('*').order('datum'),sb.from('projekte').select('id,name')]);const yr=_kalNav.yr,mo=_kalNav.mo;const firstDay=new Date(yr,mo,1).getDay();const dim=new Date(yr,mo+1,0).getDate();const monate=['Januar','Februar','März','April','Mai','Juni','Juli','August','September','Oktober','November','Dezember'];let cc='';const pad=n=>String(n).padStart(2,'0');for(let i=0;i<(firstDay===0?6:firstDay-1);i++)cc+=`<div class="cal-day" style="background:var(--bg)"></div>`;for(let d=1;d<=dim;d++){const ds=`${yr}-${pad(mo+1)}-${pad(d)}`;const de=(data||[]).filter(t=>t.datum===ds);const it=ds===heute();cc+=`<div class="cal-day${it?' today':''}" onclick='mTermin("${ds}",${JSON.stringify(proj||[]).replace(/"/g,"&quot;")})'><div class="cal-dn${it?' cur':''}">${d}</div>${de.slice(0,2).map(e=>`<div class="cal-ev">${e.titel||'Termin'}</div>`).join('')}</div>`;}const up=(data||[]).filter(t=>t.datum>=heute()).slice(0,10);sC(`<div class="ph"><div><div class="pt">Termine</div><div class="ps">${(data||[]).length} Einträge</div></div><button class="bp" onclick='mTermin("",${JSON.stringify(proj||[]).replace(/'/g,"&#39;")})'>+ Neuer Termin</button></div><div class="cal"><div class="cal-head" style="display:flex;align-items:center;justify-content:space-between;padding:12px 16px"><button onclick="pgTermineNav(-1)" style="background:none;border:1px solid var(--border-l);border-radius:8px;padding:5px 14px;cursor:pointer;font-size:20px;line-height:1;color:var(--text-sec)">‹</button><div style="font-size:15px;font-weight:700;color:var(--text)">${monate[mo]} ${yr}</div><button onclick="pgTermineNav(1)" style="background:none;border:1px solid var(--border-l);border-radius:8px;padding:5px 14px;cursor:pointer;font-size:20px;line-height:1;color:var(--text-sec)">›</button></div><div class="cal-grid"><div class="cal-day-h">Mo</div><div class="cal-day-h">Di</div><div class="cal-day-h">Mi</div><div class="cal-day-h">Do</div><div class="cal-day-h">Fr</div><div class="cal-day-h">Sa</div><div class="cal-day-h">So</div>${cc}</div></div><div class="sh">Kommende Termine</div><div class="tc" style="overflow-x:auto"><table><thead><tr><th>Datum</th><th>Zeit</th><th>Titel</th><th>Status</th><th></th></tr></thead><tbody>${!up.length?'<tr><td colspan="5"><div class="em" style="padding:20px"><div class="em-t">Keine Termine</div></div></td></tr>':up.map(t=>`<tr style="cursor:pointer" onclick="mTerminEdit('${t.id}','${t.titel||''}','${t.datum||''}','${t.uhrzeit||''}','${t.status||''}','${t.projekt_id||''}',${JSON.stringify(proj||[]).replace(/'/g,'&#39;').replace(/"/g,'&quot;')})"><td>${fmtDatum(t.datum)}</td><td style="color:var(--text-sec)">${t.uhrzeit||'-'}</td><td><span style="font-weight:500">${t.titel||'-'}</span></td><td><span class="bd ${t.status==='erledigt'?'bd-g':t.status==='abgesagt'?'bd-r':'bd-b'}">${t.status||'geplant'}</span></td><td><button onclick="event.stopPropagation();delTermin('${t.id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red)">🗑️</button></td></tr>`).join('')}</tbody></table></div>`);}catch(e){sC(`<div class="em"><div class="em-t">${e.message}</div></div>`);}}
function mTermin(datum,proj){oM(`${modalHeader('Neuer Termin')}<div class="fg"><label>TITEL *</label><input id="f-t" placeholder="z.B. Baustellenbegehung"></div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">- Kein Projekt -</option>${(proj||[]).map(p=>`<option value="${p.id}">${p.name}</option>`).join('')}</select></div><div class="fr"><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${datum||heute()}"></div><div class="fg"><label>UHRZEIT</label><input id="f-u" type="time" value="08:00"></div></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="geplant">Geplant</option><option value="erledigt">Erledigt</option><option value="abgesagt">Abgesagt</option></select></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveTermin('')">Speichern</button></div>`);}
function mTerminEdit(id,titel,datum,uhrzeit,status,pid,proj){oM(`${modalHeader('Termin bearbeiten')}<div class="fg"><label>TITEL *</label><input id="f-t" value="${titel}"></div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">- Kein Projekt -</option>${(proj||[]).map(p=>`<option value="${p.id}"${p.id===pid?' selected':''}>${p.name}</option>`).join('')}</select></div><div class="fr"><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${datum||heute()}"></div><div class="fg"><label>UHRZEIT</label><input id="f-u" type="time" value="${uhrzeit||'08:00'}"></div></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="geplant"${status==='geplant'?' selected':''}>Geplant</option><option value="erledigt"${status==='erledigt'?' selected':''}>Erledigt</option><option value="abgesagt"${status==='abgesagt'?' selected':''}>Abgesagt</option></select></div><div class="ma"><button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delTermin('${id}')">Löschen</button><button class="bs" onclick="saveTermin('${id}')">Speichern</button></div>`);}
function pgTermineNav(dir){_kalNav.mo+=dir;if(_kalNav.mo>11){_kalNav.mo=0;_kalNav.yr++;}if(_kalNav.mo<0){_kalNav.mo=11;_kalNav.yr--;}pgTermine();}
async function saveTermin(id){const t=document.getElementById('f-t').value.trim();if(!t){alert('Titel fehlt!');return;}const o={titel:t,projekt_id:document.getElementById('f-p').value||null,datum:document.getElementById('f-d').value,uhrzeit:document.getElementById('f-u').value,status:document.getElementById('f-s').value,user_id:me.id};const{error}=id?await sb.from('termine').update(o).eq('id',id):await sb.from('termine').insert(o);if(error){alert('Fehler: '+error.message);return;}cM();pgTermine();}
async function delTermin(id){if(!confirm('Termin löschen?'))return;await sb.from('termine').delete().eq('id',id);cM();pgTermine();}
let _angAllData=[];
let _angSel={active:false,ids:new Set()};
function renderAngCards(ang){
  const sel=_angSel;
  const check=(id)=>`<div style="width:24px;height:24px;border-radius:50%;border:2px solid ${sel.ids.has(id)?'var(--p)':'var(--border)'};background:${sel.ids.has(id)?'var(--p)':'transparent'};flex-shrink:0;display:flex;align-items:center;justify-content:center">${sel.ids.has(id)?'<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="3.5"><polyline points="20 6 9 17 4 12"/></svg>':''}</div>`;
  const cards=ang.map(a=>{
    const sc=a.status==='angenommen'?'bd-g':a.status==='abgelehnt'?'bd-r':'bd-o';
    if(sel.active){
      const selected=sel.ids.has(a.id);
      return `<div class="ca" onclick="toggleAngCard('${a.id}')" style="cursor:pointer;${selected?'border:2px solid var(--p);background:var(--p-light)':''}"><div style="display:flex;align-items:flex-start;gap:12px">${check(a.id)}<div style="flex:1;min-width:0"><div style="font-family:monospace;font-size:11px;color:var(--text-ter);margin-bottom:2px">${a.nummer||'-'} · ${fmtDatum(a.datum)}</div><div class="ca-t">${a.titel||'-'}</div><div class="ca-s">${a.kunde||''}</div><div style="display:flex;justify-content:space-between;align-items:center;margin-top:6px"><span style="font-size:16px;font-weight:700;color:var(--p)">${fmtEur(a.gesamt)}</span><span class="bd ${sc}">${a.status||'offen'}</span></div></div></div></div>`;
    }
    return `<div class="ca"><div onclick="mAngEdit('${a.id}',null)" style="cursor:pointer"><div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:6px"><div style="flex:1;min-width:0"><div style="font-family:monospace;font-size:11px;color:var(--text-ter);margin-bottom:2px">${a.nummer||'-'} · ${fmtDatum(a.datum)}</div><div class="ca-t">${a.titel||'-'}</div><div class="ca-s">${a.kunde||''}</div></div><span class="bd ${sc}" style="margin-left:8px;flex-shrink:0">${a.status||'offen'}</span></div><div style="font-size:18px;font-weight:700;color:var(--p);margin:8px 0 10px">${fmtEur(a.gesamt)}</div></div><div style="display:flex;gap:8px;flex-wrap:wrap"><button onclick="exportAngPDF('${a.id}')" style="flex:1;padding:9px 12px;background:var(--p);color:#fff;border:none;border-radius:9px;font-size:13px;font-weight:600;cursor:pointer;min-width:120px">📤 PDF / Teilen</button><button onclick="angToRech('${a.id}',null)" style="flex:1;padding:9px 12px;background:var(--surface);border:1px solid var(--border);border-radius:9px;font-size:13px;font-weight:600;cursor:pointer;color:var(--text);min-width:120px">→ Rechnung</button></div></div>`;
  }).join('');
  const bottomBar=sel.active?`<div style="position:fixed;bottom:60px;left:0;right:0;background:var(--surface);border-top:1.5px solid var(--border);padding:12px 16px;display:flex;align-items:center;gap:10px;z-index:200;box-shadow:0 -4px 16px rgba(0,0,0,0.12)"><div style="flex:1;font-size:14px;font-weight:600;color:var(--text)">${sel.ids.size} ausgewählt</div><button onclick="delAngSel()" ${!sel.ids.size?'disabled':''} style="padding:9px 18px;background:${sel.ids.size?'var(--red)':'var(--border)'};color:#fff;border:none;border-radius:9px;font-size:13px;font-weight:600;cursor:pointer">Löschen</button><button onclick="stopAngSel()" style="padding:9px 18px;background:var(--bg);border:1px solid var(--border);border-radius:9px;font-size:13px;font-weight:600;cursor:pointer;color:var(--text)">Abbrechen</button></div><div style="height:72px"></div>`:'';
  return `<div class="gr">${ang.length?cards:'<div class="em"><div class="em-t">Keine Angebote</div><div class="em-s">Erstelle dein erstes Angebot über den Button oben</div></div>'}</div>${bottomBar}`;
}
function startAngSel(){_angSel={active:true,ids:new Set()};document.getElementById('ang-wrap').innerHTML=renderAngCards(_angAllData);}
function stopAngSel(){_angSel={active:false,ids:new Set()};document.getElementById('ang-wrap').innerHTML=renderAngCards(_angAllData);}
function toggleAngCard(id){if(_angSel.ids.has(id))_angSel.ids.delete(id);else _angSel.ids.add(id);document.getElementById('ang-wrap').innerHTML=renderAngCards(_angAllData);}
async function delAngSel(){if(!_angSel.ids.size)return;if(!confirm(_angSel.ids.size+' Angebot(e) löschen?'))return;for(const id of _angSel.ids){await sb.from('angebote').delete().eq('id',id);}stopAngSel();pgAngebote();}
async function exportAngPDF(aid){const{data:a}=await sb.from('angebote').select('*').eq('id',aid).single();if(!a){alert('Angebot nicht gefunden');return;}const{jsPDF}=window.jspdf;const doc=new jsPDF();const blau=[37,99,235],grau=[107,114,128];const L=20,R=190,W=170;const pos=JSON.parse(a.positionen||'[]');doc.setFillColor(249,250,251);doc.rect(0,0,210,297,'F');doc.setFillColor(255,255,255);doc.roundedRect(L-5,12,W+10,38,3,3,'F');doc.setDrawColor(229,231,235);doc.roundedRect(L-5,12,W+10,38,3,3,'S');doc.setTextColor(...blau);doc.setFontSize(20);doc.setFont('helvetica','bold');doc.text('ANGEBOT',L,28);doc.setFontSize(9);doc.setFont('helvetica','normal');doc.setTextColor(...grau);doc.text(a.nummer||'-',L,36);doc.text(settings.firma||'',R,24,'right');doc.text(settings.adresse||'',R,31,'right');doc.text('Datum: '+fmtDatum(a.datum),R,38,'right');let y=64;doc.setFillColor(255,255,255);doc.roundedRect(L-5,y-6,W+10,24,3,3,'F');doc.setDrawColor(229,231,235);doc.roundedRect(L-5,y-6,W+10,24,3,3,'S');doc.setFontSize(8);doc.setFont('helvetica','bold');doc.setTextColor(...grau);doc.text('AUFTRAGGEBER',L,y+1);doc.setFont('helvetica','normal');doc.setTextColor(17,24,39);doc.setFontSize(12);doc.text(a.kunde||'-',L,y+11);y+=36;doc.setDrawColor(229,231,235);doc.line(L,y,R,y);y+=8;doc.setFontSize(8);doc.setFont('helvetica','bold');doc.setTextColor(...grau);doc.text('LEISTUNGSVERZEICHNIS',L,y);y+=6;doc.setFillColor(249,250,251);doc.rect(L-5,y,W+10,8,'F');doc.setFontSize(9);doc.setFont('helvetica','bold');doc.setTextColor(...grau);doc.text('Pos.',L,y+5);doc.text('Beschreibung',L+14,y+5);doc.text('Betrag',R,y+5,'right');y+=12;let netto=0;doc.setFont('helvetica','normal');doc.setTextColor(17,24,39);doc.setFontSize(10);pos.forEach((p,i)=>{doc.text(String(i+1)+'.',L,y);doc.text(String(p.name||'-').substring(0,55),L+14,y);doc.text(fmtEur(p.preis||0),R,y,'right');netto+=parseFloat(p.preis)||0;y+=9;if(y>250){doc.addPage();y=20;}});y+=4;doc.setDrawColor(229,231,235);doc.line(L,y,R,y);y+=8;const mwstSatz=settings.mwst||19;const mwstBetrag=netto*(mwstSatz/100);const brutto=netto+mwstBetrag;doc.setFontSize(9);doc.setTextColor(...grau);doc.text('Nettobetrag',L,y);doc.text(fmtEur(netto),R,y,'right');y+=7;doc.text('MwSt ('+mwstSatz+' %)',L,y);doc.text(fmtEur(mwstBetrag),R,y,'right');y+=10;doc.setDrawColor(229,231,235);doc.line(L,y,R,y);y+=8;doc.setFont('helvetica','bold');doc.setTextColor(17,24,39);doc.setFontSize(14);doc.text('Gesamtbetrag',L,y);doc.text(fmtEur(brutto),R,y,'right');y+=16;if(y<260){doc.setFillColor(239,246,255);doc.roundedRect(L-5,y-4,W+10,20,3,3,'F');doc.setFontSize(9);doc.setFont('helvetica','normal');doc.setTextColor(...blau);doc.text('Dieses Angebot ist 30 Tage gültig.',L,y+4);doc.setTextColor(...grau);doc.text('Wir freuen uns auf Ihren Auftrag!',L,y+12);}doc.setDrawColor(229,231,235);doc.line(L,278,R,278);doc.setFontSize(7);doc.setTextColor(...grau);const footer=[settings.firma,settings.adresse,settings.telefon].filter(Boolean).join(' · ');doc.text(footer||'Baumanager',L,283);if(settings.ustid)doc.text('USt-ID: '+settings.ustid,R,283,'right');const fname='Angebot_'+(a.nummer||aid)+'.pdf';const blob=doc.output('blob');if(navigator.canShare&&navigator.canShare({files:[new File([blob],fname,{type:'application/pdf'})]})){try{await navigator.share({files:[new File([blob],fname,{type:'application/pdf'})],title:fname});}catch(e){if(e.name!=='AbortError')doc.save(fname);}}else{doc.save(fname);}}
async function pgAngebote(){ld();_angSel={active:false,ids:new Set()};try{const[{data},{data:proj}]=await Promise.all([sb.from('angebote').select('*').order('created_at',{ascending:false}),sb.from('projekte').select('id,name')]);_angAllData=data||[];const ang=_angAllData;const offen=ang.filter(a=>a.status==='offen');const angenommen=ang.filter(a=>a.status==='angenommen');const gesamtwert=ang.reduce((s,a)=>s+(parseFloat(a.gesamt)||0),0);sC(`<div class="ph"><div><div class="pt">Angebote</div><div class="ps">${ang.length} Einträge · ${fmtEur(gesamtwert)} Gesamtwert</div></div><div style="display:flex;gap:8px;align-items:center"><button onclick="startAngSel()" style="padding:7px 13px;background:var(--bg);border:1px solid var(--border);border-radius:9px;font-size:12px;font-weight:600;cursor:pointer;color:var(--text-sec)">Auswählen</button><button class="bp" onclick='mAng("","",${JSON.stringify(proj||[]).replace(/'/g,"&#39;")})'>+ Neu</button></div></div><div style="display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin-bottom:14px"><div class="kpi-card"><div class="kpi-label">Offen</div><div class="kpi-val" style="color:var(--yellow)">${offen.length}</div></div><div class="kpi-card"><div class="kpi-label">Angenommen</div><div class="kpi-val" style="color:var(--green)">${angenommen.length}</div></div><div class="kpi-card"><div class="kpi-label">Gesamtwert</div><div class="kpi-val" style="font-size:16px">${fmtEur(gesamtwert)}</div></div></div><div id="ang-wrap">${renderAngCards(ang)}</div>`);}catch(e){sC(`<div class="em"><div class="em-t">${e.message}</div></div>`);}}
function mAng(pid,kn,proj){const nr='A-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);oM(`${modalHeader('Angebot erstellen')}<div class="fr"><div class="fg"><label>ANGEBOTSNR.</label><input id="f-nr" value="${nr}"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${heute()}"></div></div><div class="fg"><label>TITEL *</label><input id="f-t" placeholder="z.B. Sanierungsarbeiten"></div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">-</option>${(proj||[]).map(p=>`<option value="${p.id}"${p.id===pid?' selected':''}>${p.name}</option>`).join('')}</select></div><div class="fg"><label>KUNDE</label><input id="f-ku" value="${kn||''}" placeholder="Kundenname"></div><div class="fg"><label>POSITIONEN</label><div id="pos-wrap"><div class="offer-row"><input placeholder="Leistung" class="pos-name"><input placeholder="Preis" type="number" class="pos-price price-inp" oninput="calcTotal()"></div></div><button type="button" onclick="addPos()" style="margin-top:6px;padding:8px 14px;background:var(--bg);border:1.5px dashed var(--border);border-radius:var(--radius);font-size:12px;font-weight:600;cursor:pointer;color:var(--text-sec);width:100%">+ Position</button><div class="offer-total">Gesamt: <span id="tot">0,00 €</span></div></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="offen">Offen</option><option value="angenommen">Angenommen</option><option value="abgelehnt">Abgelehnt</option></select></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveAng()">Speichern</button></div>`);}
function addPos(){const w=document.getElementById('pos-wrap');const r=document.createElement('div');r.className='offer-row';r.innerHTML='<input placeholder="Leistung" class="pos-name"><input placeholder="Preis" type="number" class="pos-price price-inp" oninput="calcTotal()">';w.appendChild(r);}
function calcTotal(){let t=0;document.querySelectorAll('.pos-price').forEach(p=>t+=parseFloat(p.value)||0);document.getElementById('tot').textContent=fmtEur(t);}
async function saveAng(){const t=document.getElementById('f-t').value.trim();if(!t){alert('Titel fehlt!');return;}const ns=document.querySelectorAll('.pos-name'),ps=document.querySelectorAll('.pos-price');const pos=[];let total=0;ns.forEach((n,i)=>{if(n.value.trim()){const pr=parseFloat(ps[i].value)||0;pos.push({name:n.value,preis:pr});total+=pr;}});const{error}=await sb.from('angebote').insert({nummer:document.getElementById('f-nr').value,titel:t,projekt_id:document.getElementById('f-p').value||null,kunde:document.getElementById('f-ku').value,datum:document.getElementById('f-d').value,positionen:JSON.stringify(pos),gesamt:total,status:document.getElementById('f-s').value,user_id:me.id});if(error){alert('Fehler: '+error.message);return;}cM();pgAngebote();}
async function delAngD(id){if(!confirm('Angebot löschen?'))return;await sb.from('angebote').delete().eq('id',id);pgAngebote();}
async function pgMit(){ld();try{const[{data},{data:auf}]=await Promise.all([sb.from('mitarbeiter').select('*').order('name'),sb.from('aufgaben').select('zustaendig,status').eq('status','offen')]);const aufMap={};(auf||[]).forEach(a=>{if(a.zustaendig)aufMap[a.zustaendig]=(aufMap[a.zustaendig]||0)+1;});sC(`<div class="ph"><div><div class="pt">Mitarbeiter</div><div class="ps">${(data||[]).length} Einträge</div></div><button class="bp" onclick="mMitarbeiter()">+ Neu</button></div>${!(data&&data.length)?'<div class="em"><div class="em-t">Noch keine Mitarbeiter</div></div>':`<div class="gr">${data.map(m=>`<div class="ca" onclick="pgMitDetail('${m.id}')" style="cursor:pointer"><div style="display:flex;align-items:center;gap:12px"><div style="width:38px;height:38px;background:${m.farbe||'var(--p-light)'};border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:700;color:#fff;flex-shrink:0">${(m.name||'?')[0].toUpperCase()}</div><div style="flex:1"><div class="ca-t">${m.name||'-'}</div><div class="ca-s">${m.rolle||'Mitarbeiter'}${m.stundensatz?' · '+fmtEur(m.stundensatz)+'/h':''}${aufMap[m.name]?` · <span style="color:var(--p);font-weight:700">${aufMap[m.name]} offen</span>`:''}</div></div></div></div>`).join('')}</div>`}`);}catch(e){sC(`<div class="em"><div class="em-t">${e.message}</div></div>`);}}
async function pgMitDetail(id){ld();const m=_mitarbeiter.find(x=>x.id===id);if(!m){sC('<div class="em"><div class="em-t">Nicht gefunden</div></div>');return;}try{const[{data:auf},{data:std},{data:proj}]=await Promise.all([sb.from('aufgaben').select('*').eq('zustaendig',m.name).eq('status','offen').order('faellig',{ascending:true}),sb.from('stunden').select('*').eq('mitarbeiter_name',m.name).order('datum',{ascending:false}).limit(20),sb.from('projekte').select('id,name')]);const now=new Date();const stdM=(std||[]).filter(s=>{const d=new Date(s.datum||now);return d.getFullYear()===now.getFullYear()&&d.getMonth()===now.getMonth();});const totalH=stdM.reduce((s,r)=>s+(parseFloat(r.stunden)||0),0);const totalK=stdM.reduce((s,r)=>s+(parseFloat(r.stunden)||0)*(r.stundensatz||m.stundensatz||0),0);const ueb=(auf||[]).filter(a=>a.faellig&&a.faellig<heute());const pMap={};(proj||[]).forEach(p=>pMap[p.id]=p.name);sC(`<button class="bk" onclick="pgMit()">← Zurück</button><div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:18px 16px;margin-bottom:16px;display:flex;align-items:center;gap:14px;box-shadow:var(--shadow)"><div style="width:52px;height:52px;background:${m.farbe||'var(--p)'};border-radius:14px;display:flex;align-items:center;justify-content:center;font-size:20px;font-weight:800;color:#fff;flex-shrink:0">${(m.name||'?')[0].toUpperCase()}</div><div style="flex:1"><div style="font-size:18px;font-weight:800;color:var(--text)">${m.name}</div><div style="font-size:13px;color:var(--text-sec);margin-top:2px">${m.rolle||'Mitarbeiter'}${m.stundensatz?' · '+fmtEur(m.stundensatz)+'/h':''}</div>${m.telefon?`<a href="tel:${m.telefon}" style="font-size:12px;color:var(--p);text-decoration:none;font-weight:600;display:inline-block;margin-top:4px">${m.telefon}</a>`:''}</div><button onclick='mMitarbeiter(${JSON.stringify(m).replace(/'/g,"&#39;")})' style="padding:8px 14px;background:var(--bg);border:1px solid var(--border);border-radius:9px;font-size:12px;font-weight:600;cursor:pointer;color:var(--text-sec)">Bearbeiten</button></div><div class="kpi-grid" style="margin-bottom:16px"><div class="kpi-card${ueb.length?' kpi-alert':''}"><div class="kpi-label">Offene Aufgaben</div><div class="kpi-val">${(auf||[]).length}</div>${ueb.length?`<div class="kpi-sub" style="color:var(--red)">${ueb.length} überfällig</div>`:''}</div><div class="kpi-card"><div class="kpi-label">Stunden (Monat)</div><div class="kpi-val">${totalH.toFixed(1)} h</div><div class="kpi-sub">${fmtEur(totalK)} Kosten</div></div></div><div class="section-hdr"><span class="section-hdr-title">Offene Aufgaben (${(auf||[]).length})</span></div>${!(auf&&auf.length)?'<div class="em" style="margin-bottom:16px"><div class="em-t">Keine offenen Aufgaben</div></div>':`<div class="gr" style="margin-bottom:16px">${auf.slice(0,10).map(a=>{const ue=a.faellig&&a.faellig<heute();return`<div class="ca" onclick="mAufgabeById('${a.id}')"><div style="display:flex;justify-content:space-between;align-items:flex-start"><div style="flex:1"><div class="ca-t">${a.titel}</div><div class="ca-s">${a.faellig?fmtDatum(a.faellig):'Kein Datum'}${ue?' <span style="color:var(--red);font-weight:700"> · Überfällig</span>':''}</div></div><button onclick="event.stopPropagation();erledigeAufgabe('${a.id}')" style="padding:5px 10px;background:var(--green);color:#fff;border:none;border-radius:7px;font-size:11px;font-weight:700;cursor:pointer;flex-shrink:0">✓</button></div></div>`;}).join('')}</div>`}<div class="section-hdr"><span class="section-hdr-title">Letzte Stunden</span></div>${!(std&&std.length)?'<div class="em"><div class="em-t">Keine Stunden erfasst</div></div>':`<div class="tc" style="overflow-x:auto"><table><thead><tr><th>Datum</th><th>Projekt</th><th>Stunden</th></tr></thead><tbody>${std.slice(0,10).map(s=>`<tr><td>${fmtDatum(s.datum)}</td><td style="color:var(--text-sec)">${pMap[s.projekt_id]||'—'}</td><td><b>${s.stunden||0} h</b></td></tr>`).join('')}</tbody></table></div>`}`);}catch(e){sC(`<div class="em"><div class="em-t">${e.message}</div></div>`);}}

function mMitarbeiter(m={}){const farben=['#1D4ED8','#15803D','#B45309','#DC2626','#7C3AED','#0369A1','#C2410C','#BE185D'];oM(`${modalHeader(m.id?'Mitarbeiter bearbeiten':'Neuer Mitarbeiter')}<div class="fg"><label>NAME *</label><input id="f-n" value="${m.name||''}" placeholder="Max Mustermann"></div><div class="fr"><div class="fg"><label>TELEFON</label><input id="f-tel" value="${m.telefon||''}" placeholder="+49 176 ..."></div><div class="fg"><label>ROLLE</label><select id="f-ro"><option value="Mitarbeiter"${m.rolle==='Mitarbeiter'?' selected':''}>Mitarbeiter</option><option value="Bauleiter"${m.rolle==='Bauleiter'?' selected':''}>Bauleiter</option><option value="Azubi"${m.rolle==='Azubi'?' selected':''}>Azubi</option><option value="Subunternehmer"${m.rolle==='Subunternehmer'?' selected':''}>Subunternehmer</option></select></div></div><div class="fg"><label>STUNDENSATZ (€/h)</label><input id="f-sh" type="number" step="0.5" value="${m.stundensatz||''}" placeholder="45"></div><div class="fg"><label>FARBE</label><div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:4px">${farben.map(f=>`<div onclick="document.getElementById('f-farbe').value='${f}';document.querySelectorAll('.farb-btn').forEach(b=>b.style.outline='none');this.style.outline='3px solid var(--text)';this.style.outlineOffset='2px'" class="farb-btn" style="width:28px;height:28px;border-radius:7px;background:${f};cursor:pointer;outline:${(m.farbe||'#1D4ED8')===f?'3px solid var(--text)':'none'};outline-offset:2px"></div>`).join('')}<input type="hidden" id="f-farbe" value="${m.farbe||'#1D4ED8'}"></div></div><div class="ma">${m.id?`<button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delMitarbeiter('${m.id}')">Löschen</button>`:'<button class="bc" onclick="cM()">Abbrechen</button>'}<button class="bs" onclick="saveMitarbeiter('${m.id||''}')">Speichern</button></div>`);}
async function saveMitarbeiter(id){const n=document.getElementById('f-n').value.trim();if(!n){alert('Name fehlt!');return;}const o={name:n,telefon:document.getElementById('f-tel').value,rolle:document.getElementById('f-ro').value,stundensatz:parseFloat(document.getElementById('f-sh').value)||null,farbe:document.getElementById('f-farbe').value};const{error}=id?await sb.from('mitarbeiter').update(o).eq('id',id):await sb.from('mitarbeiter').insert(o);if(error){alert('Fehler: '+error.message);return;}await loadMitarbeiter();cM();pgMit();}
async function delMitarbeiter(id){if(!confirm('Mitarbeiter löschen?'))return;await sb.from('mitarbeiter').delete().eq('id',id);await loadMitarbeiter();cM();pgMit();}
// ─── ZEITERFASSUNG TIMER ────────────────────────────────────────
let _timerInterval=null;
function timerState(){try{return JSON.parse(localStorage.getItem('_timer')||'null');}catch{return null;}}
function timerSet(s){localStorage.setItem('_timer',JSON.stringify(s));}
function timerClear(){localStorage.removeItem('_timer');if(_timerInterval){clearInterval(_timerInterval);_timerInterval=null;}}
function fmtElapsed(ms){const s=Math.floor(ms/1000),h=Math.floor(s/3600),m=Math.floor((s%3600)/60),sec=s%60;return`${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}:${String(sec).padStart(2,'0')}`;}
function timerTick(){const t=timerState();if(!t)return;const el=document.getElementById('timer-display');if(el)el.textContent=fmtElapsed(Date.now()-t.start);}
function timerStart(projId,projName,mitName){timerSet({start:Date.now(),projId,projName,mitName});if(_timerInterval)clearInterval(_timerInterval);_timerInterval=setInterval(timerTick,1000);pgStd();}
async function timerStop(){const t=timerState();if(!t)return;const elapsedH=Math.round((Date.now()-t.start)/360000)/10;timerClear();const{data:proj}=await sb.from('projekte').select('id,name');mStdAllg(proj,t.projId,t.mitName,elapsedH);}
function mTimerStart(proj){const mitOpts=_mitarbeiter.map(m=>`<option value="${m.name}">${m.name}</option>`).join('');oM(`${modalHeader('Timer starten')}<div class="fg"><label>PROJEKT (optional)</label><select id="ft-proj"><option value="">— Kein Projekt —</option>${proj.map(p=>`<option value="${p.id}|${p.name}">${p.name}</option>`).join('')}</select></div><div class="fg"><label>MITARBEITER</label><select id="ft-mit"><option value="">— Wählen —</option>${mitOpts}</select></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" style="background:var(--green)" onclick="doTimerStart()">Timer starten</button></div>`);}
function doTimerStart(){const pv=document.getElementById('ft-proj').value;const[projId,projName]=pv?pv.split('|'):['',''];const mitName=document.getElementById('ft-mit').value;cM();timerStart(projId||null,projName||null,mitName||null);}
async function pgStd(){ld();try{const[{data},{data:proj}]=await Promise.all([sb.from('stunden').select('*').order('datum',{ascending:false}),sb.from('projekte').select('id,name')]);window._stdProj=proj||[];const total=(data||[]).reduce((s,r)=>s+(parseFloat(r.stunden)||0),0);const totalKosten=(data||[]).reduce((s,r)=>{const mit=_mitarbeiter.find(m=>m.name===r.mitarbeiter_name);const satz=r.stundensatz||mit?.stundensatz||0;return s+(parseFloat(r.stunden)||0)*satz;},0);const t=timerState();const timerCard=t?`<div style="background:var(--green);border-radius:var(--radius);padding:14px 16px;margin-bottom:16px;display:flex;align-items:center;gap:14px;color:#fff"><div style="flex:1"><div style="font-size:11px;font-weight:700;letter-spacing:0.5px;opacity:0.85">TIMER LÄUFT${t.projName?' – '+t.projName:''}</div><div id="timer-display" style="font-size:28px;font-weight:800;letter-spacing:-0.5px;font-variant-numeric:tabular-nums">${fmtElapsed(Date.now()-t.start)}</div>${t.mitName?`<div style="font-size:12px;opacity:0.8">${t.mitName}</div>`:''}</div><button onclick="timerStop()" style="padding:10px 16px;background:rgba(0,0,0,0.25);border:none;border-radius:10px;color:#fff;font-weight:700;font-size:14px;cursor:pointer;flex-shrink:0">Stopp</button></div>`:`<div style="background:var(--surface);border:1.5px dashed var(--border);border-radius:var(--radius);padding:14px 16px;margin-bottom:16px;display:flex;align-items:center;gap:14px"><div style="flex:1"><div style="font-size:13px;font-weight:700;color:var(--text)">Zeiterfassung</div><div style="font-size:12px;color:var(--text-sec)">Timer starten und automatisch erfassen</div></div><button onclick="mTimerStart(window._stdProj)" style="padding:8px 16px;background:var(--green);color:#fff;border:none;border-radius:9px;font-weight:700;font-size:13px;cursor:pointer;flex-shrink:0">Starten</button></div>`;sC(`<div class="ph"><div><div class="pt">Stunden</div><div class="ps">${total.toFixed(1)} h gesamt · ${fmtEur(totalKosten)}</div></div><button class="bp" onclick="mStdAllg(window._stdProj)">+ Eintragen</button></div>${timerCard}<div class="tc" style="overflow-x:auto"><table><thead><tr><th>Datum</th><th>Mitarbeiter</th><th>Projekt</th><th>Std</th><th>Kosten</th><th></th></tr></thead><tbody>${!(data&&data.length)?'<tr><td colspan="6"><div class="em" style="padding:30px"><div class="em-t">Keine Einträge</div></div></td></tr>':data.map(s=>{const mit=_mitarbeiter.find(m=>m.name===s.mitarbeiter_name);const satz=s.stundensatz||mit?.stundensatz||0;const kosten=(parseFloat(s.stunden)||0)*satz;return`<tr><td>${fmtDatum(s.datum)}</td><td>${s.mitarbeiter_name||'-'}</td><td style="color:var(--text-sec)">${(window._stdProj||[]).find(p=>p.id===s.projekt_id)?.name||'-'}</td><td><b>${s.stunden||0} h</b></td><td>${satz>0?fmtEur(kosten):'-'}</td><td><button onclick="delStdD('${s.id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red);font-size:16px">×</button></td></tr>`;}).join('')}</tbody></table></div>`);if(t){if(_timerInterval)clearInterval(_timerInterval);_timerInterval=setInterval(timerTick,1000);}}catch(e){sC(`<div class="em"><div class="em-t">${e.message}</div></div>`);}}
function mStd2(pid){const mitOpts=_mitarbeiter.map(m=>`<option value="${m.name}" data-satz="${m.stundensatz||0}">${m.name}${m.stundensatz?' ('+fmtEur(m.stundensatz)+'/h)':''}</option>`).join('');oM(`${modalHeader('Stunden eintragen')}<input type="hidden" id="f-p" value="${pid}"><div class="fg"><label>MITARBEITER</label><select id="f-n" onchange="updateSatz(this)"><option value="">— Wählen —</option>${mitOpts}</select></div><div class="fg"><label>STUNDENSATZ (€/h)</label><input id="f-satz" type="number" step="0.5" placeholder="wird automatisch befüllt"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${heute()}"></div><div class="fg"><label>STUNDEN *</label><input id="f-s" type="number" step="0.5" min="0.5" max="24" placeholder="8"></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveStd()">Speichern</button></div>`);}
function mStdAllg(proj,prefProjId,prefMit,prefStd){const mitOpts=_mitarbeiter.map(m=>`<option value="${m.name}" data-satz="${m.stundensatz||0}"${m.name===prefMit?' selected':''}>${m.name}${m.stundensatz?' ('+fmtEur(m.stundensatz)+'/h)':''}</option>`).join('');oM(`${modalHeader('Stunden eintragen')}<div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">— Kein Projekt —</option>${(proj||[]).map(p=>`<option value="${p.id}"${p.id===prefProjId?' selected':''}>${p.name}</option>`).join('')}</select></div><div class="fg"><label>MITARBEITER</label><select id="f-n" onchange="updateSatz(this)"><option value="">— Wählen —</option>${mitOpts}</select></div><div class="fg"><label>STUNDENSATZ (€/h)</label><input id="f-satz" type="number" step="0.5" placeholder="automatisch"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${heute()}"></div><div class="fg"><label>STUNDEN *</label><input id="f-s" type="number" step="0.25" min="0.25" max="24" placeholder="8"></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveStd()">Speichern</button></div>`);if(prefStd)document.getElementById('f-s').value=prefStd;}
function updateSatz(sel){const satz=sel.options[sel.selectedIndex]?.dataset.satz||0;document.getElementById('f-satz').value=satz||'';}
async function saveStd(){const s=document.getElementById('f-s').value;const n=document.getElementById('f-n').value;if(!s){alert('Stunden fehlen!');return;}const satz=parseFloat(document.getElementById('f-satz').value)||0;const{error}=await sb.from('stunden').insert({projekt_id:document.getElementById('f-p').value||null,mitarbeiter_name:n,datum:document.getElementById('f-d').value,stunden:parseFloat(s),stundensatz:satz,kosten:(parseFloat(s)||0)*satz});if(error){alert('Fehler: '+error.message);return;}cM();pgStd();}
async function delStdD(id){if(!confirm('Eintrag löschen?'))return;await sb.from('stunden').delete().eq('id',id);pgStd();}
async function pgMat(){ld();try{const[{data},{data:proj}]=await Promise.all([sb.from('material').select('*').order('created_at',{ascending:false}),sb.from('projekte').select('id,name')]);const totalWert=(data||[]).reduce((s,r)=>s+(parseFloat(r.preis)||0),0);sC(`<div class="ph"><div><div class="pt">Material</div><div class="ps">${(data||[]).length} Einträge · ${fmtEur(totalWert)}</div></div><button class="bp" onclick='mMatAllg(${JSON.stringify(proj||[]).replace(/'/g,"&#39;")})'>+ Hinzufügen</button></div><div class="tc" style="overflow-x:auto"><table><thead><tr><th>Material</th><th>Projekt</th><th>Menge</th><th>Preis</th><th></th></tr></thead><tbody>${!(data&&data.length)?'<tr><td colspan="5"><div class="em" style="padding:30px"><div class="em-t">Kein Material</div></div></td></tr>':data.map(m=>`<tr onclick="mMatEdit('${m.id}','${m.name||''}','${m.menge||''}','${m.preis||''}')" style="cursor:pointer"><td><span style="font-weight:500">${m.name||'-'}</span></td><td style="color:var(--text-sec)">${(proj||[]).find(p=>p.id===m.projekt_id)?.name||'-'}</td><td style="color:var(--text-sec)">${m.menge||'-'}</td><td>${m.preis?fmtEur(m.preis):'-'}</td><td><button onclick="event.stopPropagation();delMatD('${m.id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red)">🗑️</button></td></tr>`).join('')}</tbody></table></div>`);}catch(e){sC(`<div class="em"><div class="em-t">${e.message}</div></div>`);}}
function mMat2(pid){oM(`${modalHeader('Material hinzufügen')}<input type="hidden" id="f-p" value="${pid}"><div class="fg"><label>MATERIALNAME *</label><input id="f-n" placeholder="z.B. Zement"></div><div class="fr"><div class="fg"><label>MENGE</label><input id="f-m" placeholder="50 Säcke"></div><div class="fg"><label>PREIS</label><input id="f-pr" type="number" step="0.01" placeholder="0,00"></div></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveMat()">Speichern</button></div>`);}
function mMatAllg(proj){oM(`${modalHeader('Material hinzufügen')}<div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">-</option>${(proj||[]).map(p=>`<option value="${p.id}">${p.name}</option>`).join('')}</select></div><div class="fg"><label>MATERIALNAME *</label><input id="f-n" placeholder="z.B. Zement"></div><div class="fr"><div class="fg"><label>MENGE</label><input id="f-m" placeholder="50 Säcke"></div><div class="fg"><label>PREIS</label><input id="f-pr" type="number" step="0.01" placeholder="0,00"></div></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveMat()">Speichern</button></div>`);}
async function saveMat(){const n=document.getElementById('f-n').value.trim();if(!n){alert('Name fehlt!');return;}const{error}=await sb.from('material').insert({projekt_id:document.getElementById('f-p').value||null,name:n,menge:document.getElementById('f-m').value,preis:parseFloat(document.getElementById('f-pr').value)||null});if(error){alert('Fehler: '+error.message);return;}cM();pgMat();}
async function delMatD(id){if(!confirm('Material löschen?'))return;await sb.from('material').delete().eq('id',id);pgMat();}
async function pgRech(){ld();try{const[{data},{data:proj}]=await Promise.all([sb.from('rechnungen').select('*').order('datum',{ascending:false}),sb.from('projekte').select('id,name')]);const paid=(data||[]).filter(r=>r.status==='bezahlt').reduce((s,r)=>s+(parseFloat(r.betrag)||0),0);const open=(data||[]).filter(r=>r.status==='offen').reduce((s,r)=>s+(parseFloat(r.betrag)||0),0);window._rProj=proj||[];sC(`<div class="ph"><div><div class="pt">Rechnungen</div><div class="ps">${(data||[]).length} Einträge</div></div><button class="bp" onclick="mRech(window._rProj)">+ Erstellen</button></div><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:16px"><div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:16px"><div style="font-size:11px;font-weight:700;color:var(--green);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px">Bezahlt</div><div style="font-size:22px;font-weight:800;color:var(--text);letter-spacing:-0.5px">${fmtEur(paid)}</div></div><div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:16px"><div style="font-size:11px;font-weight:700;color:var(--yellow);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px">Ausstehend</div><div style="font-size:22px;font-weight:800;color:var(--text);letter-spacing:-0.5px">${fmtEur(open)}</div></div></div><div class="tc" style="overflow-x:auto"><table><thead><tr><th>Nr.</th><th>Datum</th><th>Kunde</th><th>Betrag</th><th>Status</th><th></th></tr></thead><tbody>${!(data&&data.length)?'<tr><td colspan="6"><div class="em" style="padding:30px"><div class="em-t">Keine Rechnungen</div></div></td></tr>':data.map(r=>`<tr style="cursor:pointer" onclick="mRechEdit('${r.id}','${r.rechnungsnummer||''}','${r.datum||''}','${r.kunde||''}','${r.betrag||''}','${r.status||'offen'}','${r.projekt_id||''}')"><td style="font-family:monospace;font-size:11px;color:var(--text-ter);white-space:nowrap">${r.rechnungsnummer||'-'}</td><td style="white-space:nowrap">${fmtDatum(r.datum)}</td><td style="font-weight:500">${r.kunde||'-'}</td><td style="white-space:nowrap"><b>${fmtEur(r.betrag)}</b></td><td><span class="bd ${r.status==='bezahlt'?'bd-g':r.status==='offen'?'bd-o':'bd-r'}">${r.status||'offen'}</span></td><td style="white-space:nowrap"><button onclick="event.stopPropagation();exportRechPDF('${r.id}','${r.rechnungsnummer||''}','${r.datum||''}','${r.kunde||''}','${r.betrag||''}','${r.status||''}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--text-sec)" title="PDF">📄</button><button onclick="event.stopPropagation();delRech('${r.id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red)">🗑️</button></td></tr>`).join('')}</tbody></table></div>`);}catch(e){sC(`<div class="em"><div class="em-t">${e.message}</div></div>`);}}
function mRech(proj){const nr='RE-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);oM(`${modalHeader('Rechnung erstellen')}<div class="fr"><div class="fg"><label>RECHNUNGSNR.</label><input id="f-nr" value="${nr}"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${heute()}"></div></div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">-</option>${(proj||[]).map(p=>`<option value="${p.id}">${p.name}</option>`).join('')}</select></div><div class="fg"><label>KUNDE *</label><input id="f-ku" placeholder="Müller GmbH"></div><div class="fg"><label>BETRAG *</label><input id="f-b" type="number" step="0.01" placeholder="0,00"></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="offen">Offen</option><option value="bezahlt">Bezahlt</option><option value="storniert">Storniert</option></select></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveRech('')">Erstellen</button></div>`);}
function mRechEdit(id,nr,datum,kunde,betrag,status,pid){oM(`${modalHeader('Rechnung bearbeiten')}<div class="fr"><div class="fg"><label>RECHNUNGSNR.</label><input id="f-nr" value="${nr}"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${datum||heute()}"></div></div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">-</option>${(window._rProj||[]).map(p=>`<option value="${p.id}"${p.id===pid?' selected':''}>${p.name}</option>`).join('')}</select></div><div class="fg"><label>KUNDE *</label><input id="f-ku" value="${kunde}"></div><div class="fg"><label>BETRAG *</label><input id="f-b" type="number" step="0.01" value="${betrag}"></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="offen"${status==='offen'?' selected':''}>Offen</option><option value="bezahlt"${status==='bezahlt'?' selected':''}>Bezahlt</option><option value="storniert"${status==='storniert'?' selected':''}>Storniert</option></select></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveRech('${id}')">Speichern</button></div>`);}
async function saveRech(id){const ku=document.getElementById('f-ku').value.trim(),b=document.getElementById('f-b').value;if(!ku||!b){alert('Kunde und Betrag fehlen!');return;}const o={rechnungsnummer:document.getElementById('f-nr').value,projekt_id:document.getElementById('f-p').value||null,kunde:ku,datum:document.getElementById('f-d').value,betrag:parseFloat(b),status:document.getElementById('f-s').value};const{error}=id?await sb.from('rechnungen').update(o).eq('id',id):await sb.from('rechnungen').insert(o);if(error){alert('Fehler: '+error.message);return;}cM();pgRech();}
async function delRech(id){if(!confirm('Rechnung löschen?'))return;await sb.from('rechnungen').delete().eq('id',id);pgRech();}
function exportRechPDF(id,nr,datum,kunde,betrag,status){const{jsPDF}=window.jspdf;const doc=new jsPDF();const blau=[37,99,235];const grau=[107,114,128];const L=20,R=190,W=170;doc.setFillColor(249,250,251);doc.rect(0,0,210,297,'F');doc.setFillColor(255,255,255);doc.roundedRect(L-5,12,W+10,38,3,3,'F');doc.setDrawColor(229,231,235);doc.roundedRect(L-5,12,W+10,38,3,3,'S');doc.setTextColor(...blau);doc.setFontSize(20);doc.setFont('helvetica','bold');doc.text('RECHNUNG',L,28);doc.setFontSize(9);doc.setFont('helvetica','normal');doc.setTextColor(...grau);doc.text(nr,L,36);doc.text(settings.firma||'Alem Facility PRO',R,24,'right');doc.text(settings.adresse||'',R,31,'right');doc.text(fmtDatum(datum),R,38,'right');let y=64;doc.setFillColor(255,255,255);doc.roundedRect(L-5,y-6,W+10,24,3,3,'F');doc.setDrawColor(229,231,235);doc.roundedRect(L-5,y-6,W+10,24,3,3,'S');doc.setFontSize(8);doc.setFont('helvetica','bold');doc.setTextColor(...grau);doc.text('RECHNUNGSEMPFAENGER',L,y+1);doc.setFont('helvetica','normal');doc.setTextColor(17,24,39);doc.setFontSize(12);doc.text(kunde||'-',L,y+11);y+=36;doc.setDrawColor(229,231,235);doc.line(L,y,R,y);y+=8;doc.setFontSize(8);doc.setFont('helvetica','bold');doc.setTextColor(...grau);doc.text('LEISTUNGEN',L,y);y+=6;doc.setFillColor(249,250,251);doc.rect(L-5,y,W+10,8,'F');doc.setFontSize(9);doc.setFont('helvetica','bold');doc.setTextColor(...grau);doc.text('Beschreibung',L,y+5);doc.text('Betrag',R,y+5,'right');y+=12;const rechnungBetrag=parseFloat(betrag||0);const mwstSatz=settings.mwst||19;const netto=rechnungBetrag/(1+mwstSatz/100);doc.setFont('helvetica','normal');doc.setTextColor(17,24,39);doc.setFontSize(10);doc.text('Arbeitsleistung und Material',L,y);doc.text(fmtEur(netto),R,y,'right');y+=10;doc.setDrawColor(229,231,235);doc.line(L,y,R,y);y+=8;doc.setFontSize(9);doc.setTextColor(...grau);doc.text('Zwischensumme (netto)',L,y);doc.text(fmtEur(netto),R,y,'right');y+=7;const mwstBetrag=rechnungBetrag-netto;doc.text('MwSt ('+mwstSatz+' %)',L,y);doc.text(fmtEur(mwstBetrag),R,y,'right');y+=10;doc.setDrawColor(229,231,235);doc.line(L,y,R,y);y+=8;doc.setFont('helvetica','bold');doc.setTextColor(17,24,39);doc.setFontSize(14);doc.text('Gesamtbetrag',L,y);doc.text(fmtEur(rechnungBetrag),R,y,'right');y+=18;if(settings.iban){doc.setFillColor(239,246,255);doc.roundedRect(L-5,y-6,W+10,32,3,3,'F');doc.setFontSize(8);doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.text('BANKVERBINDUNG',L,y+1);y+=8;doc.setFont('helvetica','normal');doc.setTextColor(17,24,39);doc.setFontSize(10);doc.text('IBAN: '+(settings.iban||'-'),L,y);y+=6;if(settings.bank)doc.text('Bank: '+settings.bank,L,y);y+=6;if(settings.zahlungsziel)doc.text('Zahlungsziel: '+settings.zahlungsziel+' Tage',L,y);}doc.setDrawColor(229,231,235);doc.line(L,278,R,278);doc.setFontSize(7);doc.setTextColor(...grau);doc.text('Alem Facility PRO · '+new Date().toLocaleDateString('de-DE'),L,283);if(settings.ustid)doc.text('USt-ID: '+settings.ustid,R,283,'right');doc.save('Rechnung_'+nr+'.pdf');}
async function mBt(pid){const mitOpts=_mitarbeiter.map(m=>`<option value="${m.name}">${m.name}</option>`).join('');const schnell=['Maurerarbeiten','Fenster eingebaut','Elektroarbeiten','Sanitärarbeiten','Gerüst auf/abgebaut','Materiallieferung','Bauabnahme','Mangel festgestellt','Malerarbeiten','Metallbauarbeiten','Zimmerarbeiten','Dacharbeiten'];oM(`${modalHeader('Bautagesprotokoll')}<div style="background:var(--p-light);border-radius:var(--radius);padding:12px;margin-bottom:16px"><div style="display:flex;align-items:center;gap:8px"><span style="font-size:12px;color:var(--text-sec);font-weight:600">Datum:</span><input id="f-dat" type="date" value="${heute()}" style="border:none;background:transparent;font-weight:700;color:var(--p);font-size:13px;outline:none"></div></div><div class="fr"><div class="fg"><label>ZEIT VON</label><input id="f-zv" type="time" value="07:00"></div><div class="fg"><label>ZEIT BIS</label><input id="f-zb" type="time" value="16:00"></div></div><div class="fg"><label>GEWERK / FIRMA</label><input id="f-gw" placeholder="z.B. Maurer GmbH"></div><div class="fg"><label>ANWESENDE MITARBEITER</label><select id="f-mit"><option value="">— Wählen —</option>${mitOpts}</select></div><div class="fg"><label>TÄTIGKEITEN *</label><div style="display:flex;flex-wrap:wrap;gap:5px;margin-bottom:8px">${schnell.map(s=>`<button type="button" onclick="addText('f-desc','${s}')" style="padding:4px 10px;background:var(--bg);border:1.5px solid var(--border);color:var(--text-sec);border-radius:6px;font-size:11px;font-weight:500;cursor:pointer;font-family:inherit;transition:all 0.1s" onmouseover="this.style.borderColor='var(--p)';this.style.color='var(--p)'" onmouseout="this.style.borderColor='var(--border)';this.style.color='var(--text-sec)'">${s}</button>`).join('')}</div><textarea id="f-desc" rows="4" placeholder="Beschreibung der Tätigkeiten..."></textarea></div><div class="fg"><label>VERWENDETES MATERIAL</label><textarea id="f-mat" rows="2" placeholder="z.B. 50 Sack Zement..."></textarea></div><div class="fg"><label>LIEFERUNGEN</label><input id="f-lief" placeholder="z.B. Holzlieferung Firma XY"></div><div class="fg"><label>MÄNGEL / BESONDERHEITEN</label><textarea id="f-maeng" rows="2" placeholder="z.B. Riss in Wand entdeckt..."></textarea></div><div class="fg"><label>FOTOS</label><div class="photo-up" onclick="document.getElementById('bt-fi').click()"><input type="file" id="bt-fi" accept="image/*" multiple style="display:none" onchange="previewBtFotos()"><div style="font-size:20px;margin-bottom:4px">📷</div><div style="font-size:13px;font-weight:500">Fotos hinzufügen</div></div><div id="bt-fp" class="photo-prev"></div></div><div class="fg"><label>UNTERSCHRIFT BAULEITER</label><canvas id="sig-bl" width="400" height="120"></canvas><button type="button" onclick="clearSig('sig-bl')" style="padding:5px 12px;background:var(--bg);border:1.5px solid var(--border);border-radius:7px;font-size:11px;font-weight:500;cursor:pointer;color:var(--text-sec)">Löschen</button></div><div class="fg"><label>UNTERSCHRIFT AUFTRAGGEBER</label><canvas id="sig-ag" width="400" height="120"></canvas><button type="button" onclick="clearSig('sig-ag')" style="padding:5px 12px;background:var(--bg);border:1.5px solid var(--border);border-radius:7px;font-size:11px;font-weight:500;cursor:pointer;color:var(--text-sec)">Löschen</button></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveBt('${pid}')">Speichern</button></div>`);initSig('sig-bl');initSig('sig-ag');}
function addText(id,txt){const el=document.getElementById(id);el.value+=(el.value?'\n':'')+txt;}
function initSig(id){const c=document.getElementById(id);if(!c)return;const ctx=c.getContext('2d');let drawing=false;const getPos=(e)=>{const r=c.getBoundingClientRect();const t=e.touches?e.touches[0]:e;return{x:(t.clientX-r.left)*(c.width/r.width),y:(t.clientY-r.top)*(c.height/r.height)};};c.addEventListener('mousedown',e=>{drawing=true;const p=getPos(e);ctx.beginPath();ctx.moveTo(p.x,p.y);});c.addEventListener('mousemove',e=>{if(!drawing)return;const p=getPos(e);ctx.lineTo(p.x,p.y);ctx.strokeStyle='#111827';ctx.lineWidth=2;ctx.lineCap='round';ctx.stroke();});c.addEventListener('mouseup',()=>drawing=false);c.addEventListener('touchstart',e=>{e.preventDefault();drawing=true;const p=getPos(e);ctx.beginPath();ctx.moveTo(p.x,p.y);},{passive:false});c.addEventListener('touchmove',e=>{e.preventDefault();if(!drawing)return;const p=getPos(e);ctx.lineTo(p.x,p.y);ctx.strokeStyle='#111827';ctx.lineWidth=2;ctx.lineCap='round';ctx.stroke();},{passive:false});c.addEventListener('touchend',()=>drawing=false);}
function clearSig(id){const c=document.getElementById(id);c.getContext('2d').clearRect(0,0,c.width,c.height);}
function previewBtFotos(){const files=document.getElementById('bt-fi').files;const prev=document.getElementById('bt-fp');prev.innerHTML='';for(const f of files){const r=new FileReader();r.onload=e=>{const i=document.createElement('img');i.src=e.target.result;i.className='pt-img';i.onclick=()=>window.open(e.target.result,'_blank');i.style.cursor='pointer';prev.appendChild(i);};r.readAsDataURL(f);}}
async function saveBt(pid){const d=document.getElementById('f-desc').value.trim();if(!d){alert('Beschreibung fehlt!');return;}const sigBl=document.getElementById('sig-bl').toDataURL();const sigAg=document.getElementById('sig-ag').toDataURL();const dat=document.getElementById('f-dat');const mit=document.getElementById('f-mit');const{error}=await sb.from('bautagebuch').insert({projekt_id:pid,datum:dat?dat.value:heute(),beschreibung:d,gewerk:document.getElementById('f-gw').value,mitarbeiter:mit?mit.value:'',material_verwendet:document.getElementById('f-mat').value,lieferungen:document.getElementById('f-lief').value,maengel:document.getElementById('f-maeng').value,zeit_von:document.getElementById('f-zv').value,zeit_bis:document.getElementById('f-zb').value,unterschrift_bauleiter:sigBl,unterschrift_auftraggeber:sigAg,erstellt_von:me.email});if(error){alert('Fehler: '+error.message);return;}cM();pgProjDetail(pid);}
function mAbnahme(pid,pname,kunde){const mitOpts=_mitarbeiter.map(m=>`<option value="${m.name}">${m.name}</option>`).join('');oM(`${modalHeader('Abnahmeprotokoll')}<div style="background:var(--p-light);border-radius:var(--radius);padding:12px;margin-bottom:16px"><div style="display:flex;justify-content:space-between;align-items:center"><span style="font-size:13px;font-weight:600;color:var(--p)">${pname||'Projekt'}</span><span style="font-size:12px;color:var(--text-sec)">${new Date().toLocaleDateString('de-DE')}</span></div></div><div class="fr"><div class="fg"><label>ORT</label><input id="f-ort" placeholder="z.B. Berlin"></div><div class="fg"><label>AUFTRAGGEBER</label><input id="f-ag" value="${kunde||''}" placeholder="Kunde / Vermieter"></div></div><div class="fg"><label>AUFTRAGNEHMER</label><input id="f-an" value="${settings.firma||''}" placeholder="Ihre Firma"></div><div class="fg"><label>BAULEITER</label><select id="f-bl"><option value="">— Wählen —</option>${mitOpts}</select></div><div class="fg"><label>ERLEDIGTE ARBEITEN</label><div style="display:flex;flex-wrap:wrap;gap:5px;margin-bottom:8px">${['Maurerarbeiten','Elektroarbeiten','Sanitärarbeiten','Malerarbeiten','Bodenbelag','Fenster eingebaut','Türen eingebaut','Dacharbeiten','Gerüstarbeiten','Sonstige Arbeiten'].map(s=>`<button type="button" onclick="addText('f-arb','${s}')" style="padding:4px 10px;background:var(--bg);border:1.5px solid var(--border);color:var(--text-sec);border-radius:6px;font-size:11px;font-weight:500;cursor:pointer;font-family:inherit;transition:all 0.1s" onmouseover="this.style.borderColor='var(--p)';this.style.color='var(--p)'" onmouseout="this.style.borderColor='var(--border)';this.style.color='var(--text-sec)'">${s}</button>`).join('')}</div><textarea id="f-arb" rows="4" placeholder="Welche Arbeiten wurden durchgeführt?"></textarea></div><div class="fg"><label>MÄNGEL</label><textarea id="f-maeng" rows="3" placeholder="Keine Mängel / oder Mängel beschreiben..."></textarea></div><div class="fg"><label>MÄNGEL FRIST</label><input id="f-frist" type="date"></div><div class="fg"><label>BEMERKUNGEN</label><textarea id="f-bem" rows="2" placeholder="Sonstige Bemerkungen..."></textarea></div><div class="fg"><label>UNTERSCHRIFT AUFTRAGNEHMER</label><canvas id="sig-an" width="400" height="120"></canvas><button type="button" onclick="clearSig('sig-an')" style="padding:5px 12px;background:var(--bg);border:1.5px solid var(--border);border-radius:7px;font-size:11px;font-weight:500;cursor:pointer;color:var(--text-sec)">Löschen</button></div><div class="fg"><label>UNTERSCHRIFT AUFTRAGGEBER</label><canvas id="sig-ag2" width="400" height="120"></canvas><button type="button" onclick="clearSig('sig-ag2')" style="padding:5px 12px;background:var(--bg);border:1.5px solid var(--border);border-radius:7px;font-size:11px;font-weight:500;cursor:pointer;color:var(--text-sec)">Löschen</button></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveAbnahme('${pid}')">Speichern & PDF</button></div>`);initSig('sig-an');initSig('sig-ag2');}
