async function pgVertraege(){ld();try{const{data}=await sb.from('vertraege').select('*').order('created_at',{ascending:false});const aktiv=(data||[]).filter(v=>v.status==='aktiv');const monatlich=aktiv.reduce((s,v)=>s+(parseFloat(v.betrag)||0),0);sC(`<div class="ph"><div><div class="pt">Verträge</div><div class="ps">${aktiv.length} aktive Verträge</div></div><button class="bp" onclick="mVertrag()">+ Neuer Vertrag</button></div><div style="display:flex;gap:8px;margin-bottom:16px"><button onclick="pgVorlagen()" style="padding:8px 14px;background:var(--bg);border:1px solid var(--border);border-radius:8px;font-size:12px;font-weight:600;cursor:pointer;color:var(--text-sec)">📄 Vorlagen verwalten</button></div></div><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:16px"><div style="background:var(--p-light);border-radius:var(--radius);padding:16px;text-align:center"><div style="font-size:11px;font-weight:700;color:var(--p);margin-bottom:4px">MONATLICH</div><div style="font-size:22px;font-weight:800;color:var(--p)">${fmtEur(monatlich)}</div></div><div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:16px;text-align:center"><div style="font-size:11px;font-weight:700;color:var(--green);margin-bottom:4px">JÄHRLICH</div><div style="font-size:22px;font-weight:800;color:var(--green)">${fmtEur(monatlich*12)}</div></div></div>${!(data&&data.length)?'<div class="em"><div class="em-i">📋</div><div class="em-t">Noch keine Verträge</div><div class="em-s">Füge deinen ersten Wartungsvertrag hinzu</div></div>':`<div class="gr">${data.map(v=>{const faellig=v.naechste_rechnung&&v.naechste_rechnung<=heute();return`<div class="ca" onclick="mVertragEdit(${JSON.stringify(v).replace(/'/g,'&#39;')})"><div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:6px"><div><div class="ca-t">${v.kunde}</div><div class="ca-s">${v.leistung}</div></div><span class="bd ${v.status==='aktiv'?'bd-g':'bd-gr'}">${v.status==='aktiv'?'Aktiv':'Pausiert'}</span></div><div style="display:flex;justify-content:space-between;align-items:center"><div style="font-size:16px;font-weight:800;color:var(--p)">${fmtEur(v.betrag)}/Monat</div>${faellig?`<button onclick="event.stopPropagation();rechnungAusVertrag('${v.id}')" style="padding:6px 12px;background:var(--green);color:#fff;border:none;border-radius:8px;font-size:12px;font-weight:600;cursor:pointer">🧾 Rechnung</button>`:`<div style="display:flex;gap:6px"><button onclick="event.stopPropagation();erstelleVertragDokument('${v.id}')" style="padding:5px 10px;background:var(--p);color:#fff;border:none;border-radius:7px;font-size:11px;font-weight:600;cursor:pointer">📄 Vertrag</button><span style="font-size:11px;color:var(--text-ter);align-self:center">nächste: ${fmtDatum(v.naechste_rechnung)}</span></div>`}</div></div>`;}).join('')}</div>`}`);}catch(e){sC(`<div class="em"><div class="em-t">Fehler: ${e.message}</div></div>`);}}
function mVertrag(){oM(`${modalHeader('Neuer Vertrag')}<div class="fg"><label>KUNDE *</label><input id="v-kunde" placeholder="Müller Hausverwaltung GmbH"></div><div class="fg"><label>LEISTUNG *</label><select id="v-leistung"><option value="Reinigung">Reinigung</option><option value="Hausmeisterservice">Hausmeisterservice</option><option value="Winterdienst">Winterdienst</option><option value="Grünpflege">Grünpflege</option><option value="Sicherheitsdienst">Sicherheitsdienst</option><option value="Sonstiges">Sonstiges</option></select></div><div class="fr"><div class="fg"><label>BETRAG (€/Monat)</label><input id="v-betrag" type="number" step="0.01" placeholder="800"></div><div class="fg"><label>INTERVALL</label><select id="v-intervall"><option value="monatlich">Monatlich</option><option value="quartalsweise">Quartalsweise</option><option value="jährlich">Jährlich</option></select></div></div><div class="fr"><div class="fg"><label>STARTDATUM</label><input id="v-start" type="date" value="${heute()}"></div><div class="fg"><label>NÄCHSTE RECHNUNG</label><input id="v-next" type="date" value="${heute()}"></div></div><div class="fg"><label>NOTIZ</label><textarea id="v-notiz" rows="2" placeholder="z.B. jeden 1. des Monats..."></textarea></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveVertrag('')">Speichern</button></div>`);}
function mVertragEdit(v){oM(`${modalHeader('Vertrag bearbeiten')}<div class="fg"><label>KUNDE *</label><input id="v-kunde" value="${v.kunde||''}"></div><div class="fg"><label>LEISTUNG *</label><select id="v-leistung"><option value="Reinigung"${v.leistung==='Reinigung'?' selected':''}>Reinigung</option><option value="Hausmeisterservice"${v.leistung==='Hausmeisterservice'?' selected':''}>Hausmeisterservice</option><option value="Winterdienst"${v.leistung==='Winterdienst'?' selected':''}>Winterdienst</option><option value="Grünpflege"${v.leistung==='Grünpflege'?' selected':''}>Grünpflege</option><option value="Sicherheitsdienst"${v.leistung==='Sicherheitsdienst'?' selected':''}>Sicherheitsdienst</option><option value="Sonstiges"${v.leistung==='Sonstiges'?' selected':''}>Sonstiges</option></select></div><div class="fr"><div class="fg"><label>BETRAG (€/Monat)</label><input id="v-betrag" type="number" step="0.01" value="${v.betrag||''}"></div><div class="fg"><label>INTERVALL</label><select id="v-intervall"><option value="monatlich"${v.intervall==='monatlich'?' selected':''}>Monatlich</option><option value="quartalsweise"${v.intervall==='quartalsweise'?' selected':''}>Quartalsweise</option><option value="jährlich"${v.intervall==='jährlich'?' selected':''}>Jährlich</option></select></div></div><div class="fr"><div class="fg"><label>STARTDATUM</label><input id="v-start" type="date" value="${v.startdatum||''}"></div><div class="fg"><label>NÄCHSTE RECHNUNG</label><input id="v-next" type="date" value="${v.naechste_rechnung||''}"></div></div><div class="fg"><label>STATUS</label><select id="v-status"><option value="aktiv"${v.status==='aktiv'?' selected':''}>Aktiv</option><option value="pausiert"${v.status==='pausiert'?' selected':''}>Pausiert</option></select></div><div class="fg"><label>NOTIZ</label><textarea id="v-notiz" rows="2">${v.notiz||''}</textarea></div><div class="ma"><button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delVertrag('${v.id}')">Löschen</button><button class="bs" onclick="saveVertrag('${v.id}')">Speichern</button></div>`);}
async function saveVertrag(id){const kunde=document.getElementById('v-kunde').value.trim();if(!kunde){alert('Kunde fehlt!');return;}const o={kunde,leistung:document.getElementById('v-leistung').value,betrag:parseFloat(document.getElementById('v-betrag').value)||0,intervall:document.getElementById('v-intervall').value,startdatum:document.getElementById('v-start').value,naechste_rechnung:document.getElementById('v-next').value||null,status:id?document.getElementById('v-status').value:'aktiv',notiz:document.getElementById('v-notiz').value,user_id:me.id};const{error}=id?await sb.from('vertraege').update(o).eq('id',id):await sb.from('vertraege').insert(o);if(error){alert('Fehler: '+error.message);return;}cM();pgVertraege();}
async function delVertrag(id){if(!confirm('Vertrag wirklich löschen?'))return;await sb.from('vertraege').delete().eq('id',id);cM();pgVertraege();}
async function rechnungAusVertrag(id){const{data:v}=await sb.from('vertraege').select('*').eq('id',id).single();if(!v)return;const nr='RE-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);const{error}=await sb.from('rechnungen').insert({rechnungsnummer:nr,kunde:v.kunde,datum:heute(),betrag:v.betrag,status:'offen',user_id:me.id});if(error){alert('Fehler: '+error.message);return;}const next=new Date();next.setMonth(next.getMonth()+1);await sb.from('vertraege').update({naechste_rechnung:next.toISOString().split('T')[0]}).eq('id',id);alert('✅ Rechnung '+nr+' erstellt!');pgVertraege();}
