async function exportAlleData(){try{const tables=['projekte','kunden','aufgaben','rechnungen','angebote','termine','stunden','material','leads','anfragen','mitarbeiter','vertraege','einstellungen'];const result={exportiert_am:new Date().toISOString(),user_id:me?.id};for(const t of tables){try{const{data}=await sb.from(t).select('*');result[t]=data||[];}catch{result[t]=[];}}const blob=new Blob([JSON.stringify(result,null,2)],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='baumanager_export_'+heute()+'.json';a.click();}catch(e){alert('Fehler beim Export: '+e.message);}}
async function deleteAccount(){if(!confirm('Achtung: Alle Daten werden unwiderruflich gelöscht. Fortfahren?'))return;if(!confirm('Letzte Bestätigung: Konto und alle Daten wirklich löschen?'))return;try{const tables=['projekte','kunden','aufgaben','rechnungen','angebote','termine','stunden','material','leads','anfragen','mitarbeiter','vertraege','einstellungen'];for(const t of tables){try{await sb.from(t).delete().eq('user_id',me.id);}catch{}}await sb.auth.signOut();location.reload();}catch(e){alert('Fehler: '+e.message);}}
