let _vorlagen=[];
async function loadVorlagen(){try{const{data}=await sb.from('vertragsvorlagen').select('*').order('name');if(data&&data.length)_vorlagen=data;else _vorlagen=DEFAULT_VORLAGEN.map(v=>({...v}));}catch(e){_vorlagen=DEFAULT_VORLAGEN.map(v=>({...v}));}}
async function pgVorlagen(){ld();await loadVorlagen();sC(`<div class="ph"><div><div class="pt">Vertragsvorlagen</div><div class="ps">Editierbare Vorlagen</div></div><button class="bp" onclick="mVorlage()">+ Neue Vorlage</button></div><div style="background:var(--yellow-bg);border:1px solid var(--yellow);border-radius:12px;padding:12px 14px;margin-bottom:16px;font-size:12px;color:var(--yellow);font-weight:600">💡 Platzhalter: {{kunde}} {{firma}} {{betrag}} {{datum}} {{startdatum}} {{leistung}} {{objekt}}</div><div class="gr">${_vorlagen.map(v=>`<div class="ca" data-v='${JSON.stringify(v).replace(/'/g,"&#39;").replace(/`/g,"&#96;")}' style="cursor:pointer"><div style="display:flex;justify-content:space-between;align-items:center"><div><div class="ca-t">${v.name}</div><div class="ca-s">${v.typ}</div></div><span style="font-size:11px;color:var(--text-ter);background:var(--bg);padding:2px 8px;border-radius:6px">Bearbeiten →</span></div></div>`).join('')}`);document.querySelectorAll('[data-v]').forEach(el=>el.addEventListener('click',()=>mVorlage(JSON.parse(el.dataset.v.replace(/&#39;/g,"'").replace(/&#96;/g,'`')))));}function mVorlage(v={}){const isEdit=!!v.id;oM(`${modalHeader(isEdit?'Vorlage bearbeiten':'Neue Vorlage')}<div class="fg"><label>NAME *</label><input id="vl-name" value="${v.name||''}" placeholder="z.B. Reinigungsvertrag"></div><div class="fg"><label>TYP</label><select id="vl-typ"><option value="reinigung"${v.typ==='reinigung'?' selected':''}>Reinigung</option><option value="hausmeister"${v.typ==='hausmeister'?' selected':''}>Hausmeister</option><option value="winterdienst"${v.typ==='winterdienst'?' selected':''}>Winterdienst</option><option value="sonstiges"${v.typ==='sonstiges'?' selected':''}>Sonstiges</option></select></div><div class="fg"><label>VERTRAGSTEXT</label><textarea id="vl-inhalt" rows="20" style="font-family:monospace;font-size:12px">${v.inhalt||''}</textarea></div><div class="ma">${isEdit?`<button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delVorlage('${v.id}')">Löschen</button>`:'<button class="bc" onclick="cM()">Abbrechen</button>'}<button class="bs" onclick="saveVorlage('${v.id||''}')">Speichern</button></div>`);}
async function saveVorlage(id){const name=document.getElementById('vl-name').value.trim();if(!name){alert('Name fehlt!');return;}const o={name,typ:document.getElementById('vl-typ').value,inhalt:document.getElementById('vl-inhalt').value,user_id:me.id};const{error}=id?await sb.from('vertragsvorlagen').update(o).eq('id',id):await sb.from('vertragsvorlagen').insert(o);if(error){alert('Fehler: '+error.message);return;}await loadVorlagen();cM();pgVorlagen();}
async function delVorlage(id){if(!confirm('Vorlage löschen?'))return;await sb.from('vertragsvorlagen').delete().eq('id',id);await loadVorlagen();cM();pgVorlagen();}
async function erstelleVertragDokument(vertragId){await loadVorlagen();const{data:v}=await sb.from('vertraege').select('*').eq('id',vertragId).single();if(!v)return;const vorlagenOpts=_vorlagen.map(vl=>`<option value="${vl.id||vl.typ}">${vl.name}</option>`).join('');oM(`${modalHeader('Vertrag erstellen')}<div style="background:var(--p-light);border-radius:12px;padding:12px;margin-bottom:16px"><div style="font-size:13px;font-weight:700;color:var(--p)">${v.kunde}</div><div style="font-size:12px;color:var(--text-sec)">${v.leistung} · ${fmtEur(v.betrag)}/Monat</div></div><div class="fg"><label>VORLAGE WÄHLEN</label><select id="vd-vorlage">${vorlagenOpts}</select></div><div class="fg"><label>OBJEKT / ADRESSE</label><input id="vd-objekt" placeholder="z.B. Musterstr. 1, 12345 Berlin"></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="generiereVertrag('${vertragId}')">Vertrag generieren →</button></div>`);}
async function generiereVertrag(vertragId){const{data:v}=await sb.from('vertraege').select('*').eq('id',vertragId).single();if(!v)return;const vorlageKey=document.getElementById('vd-vorlage').value;const objekt=document.getElementById('vd-objekt').value;const vorlage=_vorlagen.find(vl=>vl.id===vorlageKey||vl.typ===vorlageKey);if(!vorlage)return;const now=new Date();const datumStr=`${now.getDate()}.${now.getMonth()+1}.${now.getFullYear()}`;let inhalt=vorlage.inhalt.replace(/{{kunde}}/g,v.kunde).replace(/{{firma}}/g,settings.firma||'Alem Facility & Ausbau Service').replace(/{{firma_adresse}}/g,settings.adresse||'Siemensstr. 30, 12247 Berlin').replace(/{{betrag}}/g,fmtEur(v.betrag)).replace(/{{datum}}/g,datumStr).replace(/{{startdatum}}/g,fmtDatum(v.startdatum)).replace(/{{leistung}}/g,v.leistung).replace(/{{objekt}}/g,objekt).replace(/{{rechnungsdatum}}/g,'1.');const{data:dok,error}=await sb.from('vertrag_dokumente').insert({vertrag_id:vertragId,inhalt,erstellt_am:heute(),user_id:me.id}).select().single();if(error){alert('Fehler: '+error.message);return;}cM();exportVertragPDF(dok,v.kunde);}
function exportVertragPDF(dok,kundenname){const{jsPDF}=window.jspdf;const doc=new jsPDF();const L=20,R=190,W=170;doc.setFillColor(249,250,251);doc.rect(0,0,210,297,'F');doc.setFontSize(10);doc.setFont('helvetica','normal');doc.setTextColor(17,24,39);const zeilen=dok.inhalt.split('\n');let y=20;zeilen.forEach(zeile=>{if(y>270){doc.addPage();doc.setFillColor(249,250,251);doc.rect(0,0,210,297,'F');y=20;}if(zeile.startsWith('§')||zeile.includes('VERTRAG')||zeile.includes('zwischen')){doc.setFont('helvetica','bold');doc.setFontSize(11);}else{doc.setFont('helvetica','normal');doc.setFontSize(10);}const lines=doc.splitTextToSize(zeile||' ',W);lines.forEach(l=>{if(y>270){doc.addPage();doc.setFillColor(249,250,251);doc.rect(0,0,210,297,'F');y=20;}doc.text(l,L,y);y+=6;});});doc.setDrawColor(229,231,235);doc.line(L,278,R,278);doc.setFontSize(7);doc.setTextColor(107,114,128);doc.text('Alem Facility & Ausbau Service · '+new Date().toLocaleDateString('de-DE'),L,283);doc.save('Vertrag_'+kundenname+'_'+heute()+'.pdf');}
sb.auth.getSession().then(({data:{session}})=>{if(session)sA(session.user);});
